(278, 13, 'csrf', 'medium', 'Missing CSRF Token in POST Form', 'A POST form was found without a visible CSRF token hidden field, which may allow Cross-Site Request Forgery attacks.', 'text-humanizer/admin/partials/thp-content-generate.php', '<form method=\"post', 'text-humanizer/admin/partials/thp-content-generate.php:8', 'Add a CSRF token hidden field to all POST forms and validate it server-side on submission.', '2026-03-20 05:50:49'),
