(292, 14, 'xss', 'medium', 'postMessage Handler Missing Origin Validation', 'A \'message\' event listener is registered but does not appear to check event.origin. Any window (including attacker-controlled iframes or popups) can send messages that will be processed without origin verification.', 'zapwp/admin/assets/js/tempdrag.js', 'window.addEventListener(\"message\", handleMessage);', 'zapwp/admin/assets/js/tempdrag.js:2477', 'Always validate the sender\'s origin: if (event.origin !== \'https://trusted.example.com\') return; inside your message handler.', '2026-03-20 06:02:56'),
(293, 14, 'redirect', 'medium', 'Client-Side Open Redirect Risk — Dynamic location Assignment', 'window.location or location.href is assigned a dynamic value (not a hardcoded string). If this value is derived from URL parameters or user input, attackers can redirect users to malicious sites.', 'zapwp/admin/assets/js/zapwp-admin.js', 'window.location.href = BASEURL + \"?page=zap-wp-flow-create&id=\" + res.id;', 'zapwp/admin/assets/js/zapwp-admin.js:111', 'Validate redirect destinations against an allowlist. Use relative paths for internal redirects. Never redirect to a URL derived from untrusted input.', '2026-03-20 06:02:56'),
(294, 14, 'redirect', 'medium', 'Client-Side Open Redirect Risk — Dynamic location Assignment', 'window.location or location.href is assigned a dynamic value (not a hardcoded string). If this value is derived from URL parameters or user input, attackers can redirect users to malicious sites.', 'zapwp/admin/assets/js/zapwp-admin.js', 'window.location.href = BASEURL + \"?page=zap-wp-flow-create&id=\" + node;', 'zapwp/admin/assets/js/zapwp-admin.js:252', 'Validate redirect destinations against an allowlist. Use relative paths for internal redirects. Never redirect to a URL derived from untrusted input.', '2026-03-20 06:02:56'),
(295, 14, 'redirect', 'medium', 'Client-Side Open Redirect Risk — Dynamic location Assignment', 'window.location or location.href is assigned a dynamic value (not a hardcoded string). If this value is derived from URL parameters or user input, attackers can redirect users to malicious sites.', 'zapwp/admin/assets/js/zapwp-admin.js', 'window.location.href = \"admin.php?page=zap-wp-dashboard\";', 'zapwp/admin/assets/js/zapwp-admin.js:290', 'Validate redirect destinations against an allowlist. Use relative paths for internal redirects. Never redirect to a URL derived from untrusted input.', '2026-03-20 06:02:56'),
(296, 14, 'xss', 'medium', 'postMessage Handler Missing Origin Validation', 'A \'message\' event listener is registered but does not appear to check event.origin. Any window (including attacker-controlled iframes or popups) can send messages that will be processed without origin verification.', 'zapwp/admin/assets/js/zap_dragflow.js', 'window.addEventListener(\"message\", handleMessage);', 'zapwp/admin/assets/js/zap_dragflow.js:3486', 'Always validate the sender\'s origin: if (event.origin !== \'https://trusted.example.com\') return; inside your message handler.', '2026-03-20 06:02:56'),
(297, 14, 'xss', 'high', 'DOM-Based XSS — URL/Referrer Data Used in Unsafe Sink', 'Data from location.href, location.search, location.hash, document.referrer, or window.name is used in a dangerous DOM sink (innerHTML, document.write, eval). This is a classic DOM-based XSS pattern — attackers can craft URLs with malicious scripts.', 'zapwp/admin/assets/js/zap_jquery.min.js', '!function(e,t){\"use strict\";\"object\"==typeof module&&\"object\"==typeof module.exports?module.exports=e.document?t(e,!0):function(e){if(!e.document)throw new Error(\"jQuery requires a window with a document\");return t(e)}:t(e)}(\"undefined\"!=typeof window?window:this,function(ie,e){\"use strict\";var oe=[…', 'zapwp/admin/assets/js/zap_jquery.min.js:2', 'Never pass URL parameters, hash values, or referrer data to innerHTML or eval. Use textContent instead of innerHTML. Use DOMPurify to sanitize any HTML from untrusted sources.', '2026-03-20 06:02:56'),
(298, 14, 'csrf', 'medium', 'Missing CSRF Token in POST Form', 'A POST form was found without a visible CSRF token hidden field, which may allow Cross-Site Request Forgery attacks.', 'zapwp/admin/views/zap_auth.php', '<form action=\"\" method=\"post', 'zapwp/admin/views/zap_auth.php:16', 'Add a CSRF token hidden field to all POST forms and validate it server-side on submission.', '2026-03-20 06:02:56'),
(299, 14, 'xxe', 'high', 'XXE Risk — XML Parsing Without Entity Disabling', 'XML is being parsed without explicitly disabling external entity loading. If attacker-controlled XML is parsed, this enables XXE attacks that can read local files (/etc/passwd), perform SSRF, or cause denial of service via billion-laughs.', 'zapwp/includes/helpers/aws_helper.php', '$xml = simplexml_load_string($response);', 'zapwp/includes/helpers/aws_helper.php:142', 'Call libxml_disable_entity_loader(true) before parsing XML, or use LIBXML_NOENT | LIBXML_NONET flags. Validate and sanitize XML input. Prefer JSON over XML for APIs.', '2026-03-20 06:02:57'),
(300, 14, 'hardcoded_secret', 'high', 'Hardcoded Password in Source Code', 'A plaintext password appears to be hardcoded directly in source code.', 'zapwp/includes/helpers/ContactFormHooks.php', '\'your-name\'=>\'name\',\'name\' => \'name\', \'yourname\' => \'name\', \'fullname\' => \'name\', \'full_name\' => \'name\', \'firstname\' => \'name\',\'first_name\' => \'name\', \'lastname\' => \'name\', \'last_name\' => \'name\', \'givenname\' => \'name\', \'given_name\' => \'name\',\'middlename\' => \'name\', \'middle_name\' => \'name\', \'nickname…', 'zapwp/includes/helpers/ContactFormHooks.php:208', 'Move credentials to environment variables (.env) or a secrets manager. Never commit plaintext secrets.', '2026-03-20 06:02:57'),
(301, 14, 'xss', 'high', 'Cross-Site Scripting (XSS) — Unescaped Output', 'User input is echoed to the page without HTML encoding, enabling reflected XSS.', 'zapwp/includes/third_party/Allautoresponders.php', 'echo $_GET[\'code\'];', 'zapwp/includes/third_party/Allautoresponders.php:860', 'Wrap output in htmlspecialchars($var, ENT_QUOTES, \'UTF-8\') before echoing user-controlled data.', '2026-03-20 06:02:57'),
(302, 14, 'insecure_crypto', 'medium', 'Weak Pseudo-Random Generator Used for Security Token', 'rand() or mt_rand() is used in a security-sensitive context (token, nonce, key, session ID). These functions are not cryptographically secure and their output is predictable, allowing attackers to guess generated values.', 'zapwp/includes/third_party/Aweber/oauth_application.php', 'return md5($timestamp.\'-\'.rand(10000,99999).\'-\'.uniqid());', 'zapwp/includes/third_party/Aweber/oauth_application.php:273', 'Use random_bytes() or random_int() for all security-sensitive random values. For tokens: bin2hex(random_bytes(32)).', '2026-03-20 06:02:57'),
(303, 14, 'exposure', 'critical', 'Dangerous Function — eval()', 'eval() executes arbitrary PHP code at runtime. If attacker-controlled data reaches eval(), it results in Remote Code Execution.', 'zapwp/includes/third_party/CampaignMonitor/class/services_json.php', '* Javascript, and can be directly eval()\'ed with no further parsing', 'zapwp/includes/third_party/CampaignMonitor/class/services_json.php:21', 'Remove eval(). Refactor using static dispatch tables or whitelisted callbacks.', '2026-03-20 06:02:57'),
(304, 14, 'exposure', 'high', 'Command Injection Risk — Shell Execution Function', 'A shell execution function is used. If user input reaches this call it enables Remote Code Execution.', 'zapwp/includes/third_party/pcloud/Curl.php', 'public function exec() {', 'zapwp/includes/third_party/pcloud/Curl.php:32', 'Avoid shell functions where possible. If necessary, use escapeshellarg()/escapeshellcmd() and whitelist allowed values.', '2026-03-20 06:02:57'),
(305, 14, 'exposure', 'high', 'Command Injection Risk — Shell Execution Function', 'A shell execution function is used. If user input reaches this call it enables Remote Code Execution.', 'zapwp/includes/third_party/pcloud/Request.php', 'return $curl->exec();', 'zapwp/includes/third_party/pcloud/Request.php:51', 'Avoid shell functions where possible. If necessary, use escapeshellarg()/escapeshellcmd() and whitelist allowed values.', '2026-03-20 06:02:57'),
(306, 14, 'exposure', 'high', 'Command Injection Risk — Shell Execution Function', 'A shell execution function is used. If user input reaches this call it enables Remote Code Execution.', 'zapwp/includes/third_party/pcloud/Request.php', 'return $curl->exec();', 'zapwp/includes/third_party/pcloud/Request.php:64', 'Avoid shell functions where possible. If necessary, use escapeshellarg()/escapeshellcmd() and whitelist allowed values.', '2026-03-20 06:02:57'),
