(324, 14, 'exposure', 'medium', 'Potentially Unsafe unserialize() Usage', 'unserialize() can be dangerous if the serialized data originates from any untrusted source (cookies, database values from user-controlled data, file uploads, etc.).', 'zapwp/wpzap-wp-autoupdate.php', 'return unserialize($request[\'body\']);', 'zapwp/wpzap-wp-autoupdate.php:115', 'Audit the source of all data passed to unserialize(). Prefer JSON for data interchange. If you must use serialize/unserialize, add a HMAC integrity check.', '2026-03-20 06:03:01'),
(325, 15, 'ssl', 'high', 'Site Does Not Use HTTPS', 'The target uses HTTP instead of HTTPS. All data (including passwords and cookies) is transmitted in plaintext and is vulnerable to interception (man-in-the-middle attacks).', 'http://192.168.29.147/member-area', NULL, 'URL scheme: http', 'Install an SSL/TLS certificate and redirect all HTTP traffic to HTTPS.§WHERE§§LOC§Step 1 — Obtain a free SSL certificate via Let\'s Encrypt\nsudo apt install certbot python3-certbot-apache\nsudo certbot --apache -d yourdomain.com§LOC§Apache — .htaccess (HTTP to HTTPS redirect)\nRewriteEngine On\nRewriteCond %{HTTPS} off\nRewriteRule ^(.*)$ https://%{HTTP_HOST}%{REQUEST_URI} [L,R=301]§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (separate server block for port 80)\nserver {\n    listen 80;\n    server_name yourdomain.com;\n    return 301 https://$host$request_uri;\n}', '2026-03-20 06:03:43'),
(326, 15, 'exposure', 'medium', 'HTTP TRACE Method Responds With 200 — Server Reflects Request Headers', 'HTTP TRACE is enabled and the server responds with 200, reflecting all request headers back in the body. This enables Cross-Site Tracing (XST) attacks.', 'http://192.168.29.147/member-area', 'TRACE request', 'Server responded 200 to TRACE with request reflected', 'Disable HTTP TRACE: Apache: TraceEnable off. Nginx: return 405 for TRACE method.', '2026-03-20 06:03:47'),
(327, 15, 'headers', 'low', 'External Stylesheet Without Subresource Integrity (SRI)', 'An external CSS file is loaded from \'https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\' without a Subresource Integrity attribute. A compromised CDN can inject malicious CSS to perform UI redressing or data exfiltration.', 'http://192.168.29.147/member-area', NULL, '&lt;link rel=&quot;stylesheet&quot; href=&quot;https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css&quot;&gt;', 'Add an integrity attribute to all external stylesheets. Generate hashes at srihash.org.', '2026-03-20 06:03:47'),
(328, 16, 'ssl', 'high', 'Site Does Not Use HTTPS', 'The target uses HTTP instead of HTTPS. All data (including passwords and cookies) is transmitted in plaintext and is vulnerable to interception (man-in-the-middle attacks).', 'http://192.168.29.147/qa/security-scanner/login', NULL, 'URL scheme: http', 'Install an SSL/TLS certificate and redirect all HTTP traffic to HTTPS.§WHERE§§LOC§Step 1 — Obtain a free SSL certificate via Let\'s Encrypt\nsudo apt install certbot python3-certbot-apache\nsudo certbot --apache -d yourdomain.com§LOC§Apache — .htaccess (HTTP to HTTPS redirect)\nRewriteEngine On\nRewriteCond %{HTTPS} off\nRewriteRule ^(.*)$ https://%{HTTP_HOST}%{REQUEST_URI} [L,R=301]§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (separate server block for port 80)\nserver {\n    listen 80;\n    server_name yourdomain.com;\n    return 301 https://$host$request_uri;\n}', '2026-03-20 06:40:17'),
(329, 16, 'headers', 'high', 'Missing HSTS Header (Strict-Transport-Security)', 'Without HSTS, browsers may connect over HTTP even when HTTPS is available, enabling downgrade attacks and cookie theft.', 'http://192.168.29.147/qa/security-scanner/login', NULL, 'Header \'strict-transport-security\' absent', 'Add the Strict-Transport-Security header to force browsers to always use HTTPS for this domain.\nValue: Strict-Transport-Security: max-age=31536000; includeSubDomains; preload§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Strict-Transport-Security: max-age=31536000; includeSubDomains; preload\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php (create a new filter or add to an existing one)\n$response->setHeader(\'Strict-Transport-Security\', \'max-age=31536000; includeSubDomains; preload\');\n// Then register in app/Config/Filters.php: $globals[\'after\'][] = \\App\\Filters\\SecurityHeaders::class;', '2026-03-20 06:40:18'),
(330, 16, 'headers', 'medium', 'Missing X-Frame-Options Header', 'Without this header the page can be embedded in an iframe on a malicious site, enabling clickjacking attacks that trick users into clicking hidden elements.', 'http://192.168.29.147/qa/security-scanner/login', NULL, 'Header \'x-frame-options\' absent', 'Add the X-Frame-Options header to prevent your pages from being embedded in iframes on other sites.\nValue: X-Frame-Options: SAMEORIGIN§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Frame-Options \"SAMEORIGIN\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Frame-Options \"SAMEORIGIN\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Frame-Options: SAMEORIGIN\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Frame-Options\', \'SAMEORIGIN\');', '2026-03-20 06:40:18'),
(331, 16, 'headers', 'low', 'Missing X-Content-Type-Options Header', 'Without this header browsers may \"sniff\" the content type and execute files as a different type, enabling MIME-type confusion attacks.', 'http://192.168.29.147/qa/security-scanner/login', NULL, 'Header \'x-content-type-options\' absent', 'Add the X-Content-Type-Options header to prevent browsers from guessing the content type.\nValue: X-Content-Type-Options: nosniff§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Content-Type-Options \"nosniff\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Content-Type-Options \"nosniff\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Content-Type-Options: nosniff\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Content-Type-Options\', \'nosniff\');', '2026-03-20 06:40:18'),
(332, 16, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'http://192.168.29.147/qa/security-scanner/login', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-20 06:40:18'),
(333, 16, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'http://192.168.29.147/qa/security-scanner/login', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-03-20 06:40:18'),
(334, 16, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'http://192.168.29.147/qa/security-scanner/login', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-03-20 06:40:18'),
(335, 16, 'input_security', 'high', 'Form Submits Data to HTTP Endpoint (Unencrypted)', 'The form submits to an HTTP URL: http://192.168.29.147/qa/security-scanner/login. Form data (including passwords and personal information) travels in plaintext.', 'http://192.168.29.147/qa/security-scanner/login', NULL, 'Form action: http://192.168.29.147/qa/security-scanner/login', 'Update the form action to use HTTPS. Ensure the entire application is served over HTTPS.', '2026-03-20 06:40:21'),
(336, 16, 'input_security', 'low', 'Password Input Missing autocomplete Attribute', 'A password field was found without autocomplete=\"off\", \"current-password\", or \"new-password\". Browsers may cache the password, which is a risk on shared devices.', 'http://192.168.29.147/qa/security-scanner/login', NULL, '&lt;input type=&quot;password&quot; name=&quot;password&quot; class=&quot;form-control&quot; placeholder=&quot;••••••••&quot; required&gt;', 'Add autocomplete=\"current-password\" for login forms or autocomplete=\"new-password\" for registration/password-change forms.', '2026-03-20 06:40:21'),
(337, 16, 'ssl', 'critical', 'Login Form on Non-HTTPS Page — Credentials Transmitted in Plaintext', 'A login form (containing a password field) was found on a page served over HTTP. All credentials submitted are transmitted unencrypted and can be intercepted by anyone on the network.', 'http://192.168.29.147/qa/security-scanner/login', NULL, 'Password form exists on HTTP page', 'Immediately enable HTTPS for all pages containing login forms. Use HTTP Strict Transport Security (HSTS) to prevent downgrade attacks.', '2026-03-20 06:40:21'),
