INSERT INTO `qa_scan_findings` (`id`, `scan_id`, `category`, `severity`, `title`, `description`, `affected_url`, `payload`, `evidence`, `remediation`, `found_at`) VALUES
(354, 19, 'exposure', 'medium', 'Type Juggling Risk — Loose Comparison (==) With User Input', 'PHP\'s loose comparison (==) with user input can lead to authentication bypass. E.g., \"0\" == false == null == \"\" == \"0abc\" in PHP\'s loose type system. Attackers can exploit this to bypass authentication or access controls.', 'autoblogging/admin/class-autoblogging-admin.php', 'if(!empty($_POST[\'action\'] == \'autoblogging_schedule_create_update\')){', 'autoblogging/admin/class-autoblogging-admin.php:1036', 'Always use strict comparison (===) when comparing user input. Be especially careful with hash_equals(), in_array (strict mode), and authentication checks.', '2026-03-20 09:12:35'),
(355, 19, 'exposure', 'medium', 'Type Juggling Risk — Loose Comparison (==) With User Input', 'PHP\'s loose comparison (==) with user input can lead to authentication bypass. E.g., \"0\" == false == null == \"\" == \"0abc\" in PHP\'s loose type system. Attackers can exploit this to bypass authentication or access controls.', 'autoblogging/admin/class-autoblogging-admin.php', 'if(isset($_POST[\'dbaction\']) && $_POST[\'dbaction\'] == \'update\'){', 'autoblogging/admin/class-autoblogging-admin.php:1092', 'Always use strict comparison (===) when comparing user input. Be especially careful with hash_equals(), in_array (strict mode), and authentication checks.', '2026-03-20 09:12:35'),
(356, 19, 'exposure', 'medium', 'Type Juggling Risk — Loose Comparison (==) With User Input', 'PHP\'s loose comparison (==) with user input can lead to authentication bypass. E.g., \"0\" == false == null == \"\" == \"0abc\" in PHP\'s loose type system. Attackers can exploit this to bypass authentication or access controls.', 'autoblogging/admin/class-autoblogging-admin.php', 'if($_POST[\'action\'] == \'autoblogging_ai_image_generation\'){', 'autoblogging/admin/class-autoblogging-admin.php:1148', 'Always use strict comparison (===) when comparing user input. Be especially careful with hash_equals(), in_array (strict mode), and authentication checks.', '2026-03-20 09:12:35'),
(357, 19, 'exposure', 'medium', 'Type Juggling Risk — Loose Comparison (==) With User Input', 'PHP\'s loose comparison (==) with user input can lead to authentication bypass. E.g., \"0\" == false == null == \"\" == \"0abc\" in PHP\'s loose type system. Attackers can exploit this to bypass authentication or access controls.', 'autoblogging/admin/class-autoblogging-admin.php', 'if(isset($_POST[\'screen\']) && $_POST[\'screen\'] == \'media-library\'){', 'autoblogging/admin/class-autoblogging-admin.php:1157', 'Always use strict comparison (===) when comparing user input. Be especially careful with hash_equals(), in_array (strict mode), and authentication checks.', '2026-03-20 09:12:35'),
(358, 19, 'insecure_crypto', 'medium', 'Weak Pseudo-Random Generator Used for Security Token', 'rand() or mt_rand() is used in a security-sensitive context (token, nonce, key, session ID). These functions are not cryptographically secure and their output is predictable, allowing attackers to guess generated values.', 'autoblogging/admin/class-autoblogging-admin.php', 'data-id=\"\'. rand().\'\" class=\"\'.$btn_cls.\'\" data-thumbnail=\"\'.$res[\'imageid\'].\'\">', 'autoblogging/admin/class-autoblogging-admin.php:1172', 'Use random_bytes() or random_int() for all security-sensitive random values. For tokens: bin2hex(random_bytes(32)).', '2026-03-20 09:12:35'),
(359, 19, 'xss', 'high', 'Cross-Site Scripting (XSS) — Unescaped Output', 'User input is echoed to the page without HTML encoding, enabling reflected XSS.', 'autoblogging/admin/class-autoblogging-admin.php', '//echo $_POST[\'postid\']; die();', 'autoblogging/admin/class-autoblogging-admin.php:1576', 'Wrap output in htmlspecialchars($var, ENT_QUOTES, \'UTF-8\') before echoing user-controlled data.', '2026-03-20 09:12:35'),
(360, 19, 'xss', 'high', 'Cross-Site Scripting (XSS) — Unescaped Output', 'User input is echoed to the page without HTML encoding, enabling reflected XSS.', 'autoblogging/admin/class-autoblogging-admin.php', 'echo json_encode(array(\'status\' => \'success\', \'url\' => $_POST[\'tumbnail\']));', 'autoblogging/admin/class-autoblogging-admin.php:1613', 'Wrap output in htmlspecialchars($var, ENT_QUOTES, \'UTF-8\') before echoing user-controlled data.', '2026-03-20 09:12:35'),
(361, 19, 'exposure', 'medium', 'Type Juggling Risk — Loose Comparison (==) With User Input', 'PHP\'s loose comparison (==) with user input can lead to authentication bypass. E.g., \"0\" == false == null == \"\" == \"0abc\" in PHP\'s loose type system. Attackers can exploit this to bypass authentication or access controls.', 'autoblogging/admin/class-autoblogging-admin.php', 'if($_POST[\'action\'] == \'autoblogging_topic_generation\'){', 'autoblogging/admin/class-autoblogging-admin.php:1677', 'Always use strict comparison (===) when comparing user input. Be especially careful with hash_equals(), in_array (strict mode), and authentication checks.', '2026-03-20 09:12:35'),
(362, 19, 'exposure', 'medium', 'Type Juggling Risk — Loose Comparison (==) With User Input', 'PHP\'s loose comparison (==) with user input can lead to authentication bypass. E.g., \"0\" == false == null == \"\" == \"0abc\" in PHP\'s loose type system. Attackers can exploit this to bypass authentication or access controls.', 'autoblogging/admin/class-autoblogging-admin.php', 'if($_POST[\'action\'] == \'autoblogging_keyword_generation\'){', 'autoblogging/admin/class-autoblogging-admin.php:1734', 'Always use strict comparison (===) when comparing user input. Be especially careful with hash_equals(), in_array (strict mode), and authentication checks.', '2026-03-20 09:12:35'),
(363, 19, 'exposure', 'medium', 'Type Juggling Risk — Loose Comparison (==) With User Input', 'PHP\'s loose comparison (==) with user input can lead to authentication bypass. E.g., \"0\" == false == null == \"\" == \"0abc\" in PHP\'s loose type system. Attackers can exploit this to bypass authentication or access controls.', 'autoblogging/admin/class-autoblogging-admin.php', 'if($_POST[\'action\'] == \'autoblogging_keyword_generation_using_ck\'){', 'autoblogging/admin/class-autoblogging-admin.php:1764', 'Always use strict comparison (===) when comparing user input. Be especially careful with hash_equals(), in_array (strict mode), and authentication checks.', '2026-03-20 09:12:35'),
(364, 19, 'exposure', 'medium', 'Type Juggling Risk — Loose Comparison (==) With User Input', 'PHP\'s loose comparison (==) with user input can lead to authentication bypass. E.g., \"0\" == false == null == \"\" == \"0abc\" in PHP\'s loose type system. Attackers can exploit this to bypass authentication or access controls.', 'autoblogging/admin/class-autoblogging-admin.php', 'if($_POST[\'tab\'] == \'tab2\'){', 'autoblogging/admin/class-autoblogging-admin.php:1785', 'Always use strict comparison (===) when comparing user input. Be especially careful with hash_equals(), in_array (strict mode), and authentication checks.', '2026-03-20 09:12:35'),
(365, 19, 'xxe', 'high', 'XXE Risk — XML Parsing Without Entity Disabling', 'XML is being parsed without explicitly disabling external entity loading. If attacker-controlled XML is parsed, this enables XXE attacks that can read local files (/etc/passwd), perform SSRF, or cause denial of service via billion-laughs.', 'autoblogging/admin/class-autoblogging-admin.php', '$dom = new DOMDocument();', 'autoblogging/admin/class-autoblogging-admin.php:1975', 'Call libxml_disable_entity_loader(true) before parsing XML, or use LIBXML_NOENT | LIBXML_NONET flags. Validate and sanitize XML input. Prefer JSON over XML for APIs.', '2026-03-20 09:12:35'),
(366, 19, 'redirect', 'medium', 'Client-Side Open Redirect Risk — Dynamic location Assignment', 'window.location or location.href is assigned a dynamic value (not a hardcoded string). If this value is derived from URL parameters or user input, attackers can redirect users to malicious sites.', 'autoblogging/admin/js/autoblogging-admin.js', 'window.location.href = url;', 'autoblogging/admin/js/autoblogging-admin.js:1199', 'Validate redirect destinations against an allowlist. Use relative paths for internal redirects. Never redirect to a URL derived from untrusted input.', '2026-03-20 09:12:36'),
(367, 19, 'csrf', 'medium', 'Missing CSRF Token in POST Form', 'A POST form was found without a visible CSRF token hidden field, which may allow Cross-Site Request Forgery attacks.', 'autoblogging/admin/partials/autoblogging-auth-display.php', '<form action=\"\" method=\"post', 'autoblogging/admin/partials/autoblogging-auth-display.php:18', 'Add a CSRF token hidden field to all POST forms and validate it server-side on submission.', '2026-03-20 09:12:36'),
(368, 19, 'exposure', 'medium', 'Potentially Unsafe unserialize() Usage', 'unserialize() can be dangerous if the serialized data originates from any untrusted source (cookies, database values from user-controlled data, file uploads, etc.).', 'autoblogging/auto-wp-autoupdate.php', 'return unserialize($request[\'body\']);', 'autoblogging/auto-wp-autoupdate.php:115', 'Audit the source of all data passed to unserialize(). Prefer JSON for data interchange. If you must use serialize/unserialize, add a HMAC integrity check.', '2026-03-20 09:12:36'),
(369, 20, 'csrf', 'medium', 'Missing CSRF Token in POST Form', 'A POST form was found without a visible CSRF token hidden field, which may allow Cross-Site Request Forgery attacks.', 'text-humanizer/admin/partials/thp-content-generate.php', '<form method=\"post', 'text-humanizer/admin/partials/thp-content-generate.php:8', 'Add a CSRF token hidden field to all POST forms and validate it server-side on submission.', '2026-03-20 12:43:37'),
(370, 20, 'csrf', 'medium', 'Missing CSRF Token in POST Form', 'A POST form was found without a visible CSRF token hidden field, which may allow Cross-Site Request Forgery attacks.', 'text-humanizer/admin/partials/thp-content.php', '<form method=\"post', 'text-humanizer/admin/partials/thp-content.php:4', 'Add a CSRF token hidden field to all POST forms and validate it server-side on submission.', '2026-03-20 12:43:37'),
(371, 20, 'csrf', 'medium', 'Missing CSRF Token in POST Form', 'A POST form was found without a visible CSRF token hidden field, which may allow Cross-Site Request Forgery attacks.', 'text-humanizer/admin/partials/thp-setting.php', '<form method=\"post', 'text-humanizer/admin/partials/thp-setting.php:8', 'Add a CSRF token hidden field to all POST forms and validate it server-side on submission.', '2026-03-20 12:43:37'),
(372, 20, 'exposure', 'medium', 'Type Juggling Risk — Loose Comparison (==) With User Input', 'PHP\'s loose comparison (==) with user input can lead to authentication bypass. E.g., \"0\" == false == null == \"\" == \"0abc\" in PHP\'s loose type system. Attackers can exploit this to bypass authentication or access controls.', 'text-humanizer/admin/thp-admin.php', 'if(isset($_POST[\'action\']) && $_POST[\'action\'] == \'thp_addsettings\' ){', 'text-humanizer/admin/thp-admin.php:188', 'Always use strict comparison (===) when comparing user input. Be especially careful with hash_equals(), in_array (strict mode), and authentication checks.', '2026-03-20 12:43:37'),
(373, 20, 'exposure', 'medium', 'Type Juggling Risk — Loose Comparison (==) With User Input', 'PHP\'s loose comparison (==) with user input can lead to authentication bypass. E.g., \"0\" == false == null == \"\" == \"0abc\" in PHP\'s loose type system. Attackers can exploit this to bypass authentication or access controls.', 'text-humanizer/admin/thp-admin.php', 'if(isset($_POST[\'upType\']) && $_POST[\'upType\']==\"Update\"){', 'text-humanizer/admin/thp-admin.php:201', 'Always use strict comparison (===) when comparing user input. Be especially careful with hash_equals(), in_array (strict mode), and authentication checks.', '2026-03-20 12:43:37'),
(374, 21, 'headers', 'high', 'Missing HSTS Header (Strict-Transport-Security)', 'Without HSTS, browsers may connect over HTTP even when HTTPS is available, enabling downgrade attacks and cookie theft.', 'https://nicedefenceacademy.com', NULL, 'Header \'strict-transport-security\' absent', 'Add the Strict-Transport-Security header to force browsers to always use HTTPS for this domain.\nValue: Strict-Transport-Security: max-age=31536000; includeSubDomains; preload§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Strict-Transport-Security: max-age=31536000; includeSubDomains; preload\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php (create a new filter or add to an existing one)\n$response->setHeader(\'Strict-Transport-Security\', \'max-age=31536000; includeSubDomains; preload\');\n// Then register in app/Config/Filters.php: $globals[\'after\'][] = \\App\\Filters\\SecurityHeaders::class;', '2026-03-20 13:48:05'),
(375, 21, 'headers', 'medium', 'Missing X-Frame-Options Header', 'Without this header the page can be embedded in an iframe on a malicious site, enabling clickjacking attacks that trick users into clicking hidden elements.', 'https://nicedefenceacademy.com', NULL, 'Header \'x-frame-options\' absent', 'Add the X-Frame-Options header to prevent your pages from being embedded in iframes on other sites.\nValue: X-Frame-Options: SAMEORIGIN§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Frame-Options \"SAMEORIGIN\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Frame-Options \"SAMEORIGIN\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Frame-Options: SAMEORIGIN\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Frame-Options\', \'SAMEORIGIN\');', '2026-03-20 13:48:05'),
(376, 21, 'headers', 'low', 'Missing X-Content-Type-Options Header', 'Without this header browsers may \"sniff\" the content type and execute files as a different type, enabling MIME-type confusion attacks.', 'https://nicedefenceacademy.com', NULL, 'Header \'x-content-type-options\' absent', 'Add the X-Content-Type-Options header to prevent browsers from guessing the content type.\nValue: X-Content-Type-Options: nosniff§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Content-Type-Options \"nosniff\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Content-Type-Options \"nosniff\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Content-Type-Options: nosniff\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Content-Type-Options\', \'nosniff\');', '2026-03-20 13:48:05'),
(377, 21, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://nicedefenceacademy.com', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-20 13:48:05'),
(378, 21, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'https://nicedefenceacademy.com', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-03-20 13:48:05'),
(379, 21, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://nicedefenceacademy.com', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-03-20 13:48:05'),
(380, 21, 'cookies', 'medium', 'Cookie \'ci_session\' Missing HttpOnly Flag', 'The cookie \'ci_session\' can be read by JavaScript. If an XSS vulnerability exists, attackers can steal session cookies and impersonate users.', 'https://nicedefenceacademy.com', NULL, 'Set-Cookie: ci_session=a%3A5%3A%7Bs%3A10%3A%22session_id%22%3Bs%3A32%3A%221e32e0f1f5aa942aa05337de17fde61e%22%3Bs%3A10%3A%22ip_address%22%3Bs%3A14%3A%22115.246.51.114%22%3Bs%3A10%3A%22user_agent%22%3Bs%3A60%3A%22Mozilla%2F5.0%20%28Windows%20NT%2010.0%3B%20Win64%3B%20x64%29%20AppleWebKit%2F537.36%22%3Bs%3A13%3A%22last_activity%22%3Bi%3A1774014482%3Bs%3A9%3A%22user_data%22%3Bs%3A0%3A%22%22%3B%7Da331e84bd64a812077c296f9fdc47fb4939eee08; expires=Fri, 20-Mar-2026 15:48:02 GMT; Max-Age=7200; path=/', 'Set the HttpOnly flag on the \'ci_session\' cookie to prevent client-side JavaScript from accessing it.§WHERE§§LOC§CodeIgniter 4 — app/Config/Session.php\npublic bool $cookieHTTPOnly = true;§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'httponly\' => true, \'secure\' => true, \'samesite\' => \'Lax\']);\n// Or via setcookie(): setcookie(\'ci_session\', $value, [\'httponly\' => true, \'secure\' => true]);§LOC§Apache — .htaccess (override PHP session settings)\nphp_flag session.cookie_httponly 1', '2026-03-20 13:48:05'),
(381, 21, 'cookies', 'low', 'Cookie \'ci_session\' Missing Secure Flag', 'The cookie \'ci_session\' can be sent over unencrypted HTTP connections, making it vulnerable to interception.', 'https://nicedefenceacademy.com', NULL, 'Set-Cookie: ci_session=a%3A5%3A%7Bs%3A10%3A%22session_id%22%3Bs%3A32%3A%221e32e0f1f5aa942aa05337de17fde61e%22%3Bs%3A10%3A%22ip_address%22%3Bs%3A14%3A%22115.246.51.114%22%3Bs%3A10%3A%22user_agent%22%3Bs%3A60%3A%22Mozilla%2F5.0%20%28Windows%20NT%2010.0%3B%20Win64%3B%20x64%29%20AppleWebKit%2F537.36%22%3Bs%3A13%3A%22last_activity%22%3Bi%3A1774014482%3Bs%3A9%3A%22user_data%22%3Bs%3A0%3A%22%22%3B%7Da331e84bd64a812077c296f9fdc47fb4939eee08; expires=Fri, 20-Mar-2026 15:48:02 GMT; Max-Age=7200; path=/', 'Set the Secure flag on the \'ci_session\' cookie to ensure it is transmitted only over HTTPS connections.§WHERE§§LOC§CodeIgniter 4 — app/Config/Session.php\npublic bool $cookieSecure = true;§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'secure\' => true, \'httponly\' => true, \'samesite\' => \'Lax\']);§LOC§Apache — .htaccess (PHP flag override)\nphp_flag session.cookie_secure 1', '2026-03-20 13:48:05'),
(382, 21, 'cookies', 'low', 'Cookie \'ci_session\' Missing SameSite Attribute', 'Without SameSite, the cookie is sent on cross-site requests, making it vulnerable to CSRF attacks.', 'https://nicedefenceacademy.com', NULL, 'Set-Cookie: ci_session=a%3A5%3A%7Bs%3A10%3A%22session_id%22%3Bs%3A32%3A%221e32e0f1f5aa942aa05337de17fde61e%22%3Bs%3A10%3A%22ip_address%22%3Bs%3A14%3A%22115.246.51.114%22%3Bs%3A10%3A%22user_agent%22%3Bs%3A60%3A%22Mozilla%2F5.0%20%28Windows%20NT%2010.0%3B%20Win64%3B%20x64%29%20AppleWebKit%2F537.36%22%3Bs%3A13%3A%22last_activity%22%3Bi%3A1774014482%3Bs%3A9%3A%22user_data%22%3Bs%3A0%3A%22%22%3B%7Da331e84bd64a812077c296f9fdc47fb4939eee08; expires=Fri, 20-Mar-2026 15:48:02 GMT; Max-Age=7200; path=/', 'Set the SameSite attribute on the \'ci_session\' cookie to restrict it from being sent on cross-site requests.§WHERE§§LOC§CodeIgniter 4 — app/Config/Cookie.php\npublic string $samesite = \'Lax\';  // Accepted values: \'Strict\', \'Lax\', or \'None\'§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'samesite\' => \'Lax\', \'secure\' => true, \'httponly\' => true]);§LOC§Apache — .htaccess\nphp_value session.cookie_samesite Lax', '2026-03-20 13:48:05'),
(383, 21, 'cookies', 'medium', 'Cookie \'showEpopup\' Missing HttpOnly Flag', 'The cookie \'showEpopup\' can be read by JavaScript. If an XSS vulnerability exists, attackers can steal session cookies and impersonate users.', 'https://nicedefenceacademy.com', NULL, 'Set-Cookie: showEpopup=147; expires=Fri, 20-Mar-2026 14:04:42 GMT; Max-Age=1000; path=/', 'Set the HttpOnly flag on the \'showEpopup\' cookie to prevent client-side JavaScript from accessing it.§WHERE§§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'httponly\' => true, \'secure\' => true, \'samesite\' => \'Lax\']);\n// Or via setcookie(): setcookie(\'showEpopup\', $value, [\'httponly\' => true, \'secure\' => true]);§LOC§Apache — .htaccess (override PHP session settings)\nphp_flag session.cookie_httponly 1', '2026-03-20 13:48:05'),
(384, 21, 'cookies', 'low', 'Cookie \'showEpopup\' Missing Secure Flag', 'The cookie \'showEpopup\' can be sent over unencrypted HTTP connections, making it vulnerable to interception.', 'https://nicedefenceacademy.com', NULL, 'Set-Cookie: showEpopup=147; expires=Fri, 20-Mar-2026 14:04:42 GMT; Max-Age=1000; path=/', 'Set the Secure flag on the \'showEpopup\' cookie to ensure it is transmitted only over HTTPS connections.§WHERE§§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'secure\' => true, \'httponly\' => true, \'samesite\' => \'Lax\']);§LOC§Apache — .htaccess (PHP flag override)\nphp_flag session.cookie_secure 1', '2026-03-20 13:48:05'),
(385, 21, 'cookies', 'low', 'Cookie \'showEpopup\' Missing SameSite Attribute', 'Without SameSite, the cookie is sent on cross-site requests, making it vulnerable to CSRF attacks.', 'https://nicedefenceacademy.com', NULL, 'Set-Cookie: showEpopup=147; expires=Fri, 20-Mar-2026 14:04:42 GMT; Max-Age=1000; path=/', 'Set the SameSite attribute on the \'showEpopup\' cookie to restrict it from being sent on cross-site requests.§WHERE§§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'samesite\' => \'Lax\', \'secure\' => true, \'httponly\' => true]);§LOC§Apache — .htaccess\nphp_value session.cookie_samesite Lax', '2026-03-20 13:48:05'),
(386, 21, 'exposure', 'medium', 'phpinfo() Page Exposed', 'A phpinfo() page is publicly accessible. It reveals PHP version, loaded modules, file paths, environment variables and security configuration — all useful for an attacker.', 'https://nicedefenceacademy.com/phpinfo.php', NULL, '\n\n\nbody {background-color: #fff; color: #222; font-family: sans-serif;}\npre {margin: 0; font-family: monospace;}\na:link {color: #009; text-decoration:', 'Remove this file from the production server immediately.§WHERE§§LOC§Delete the file via SSH\nrm /var/www/yourdomain/public/phpinfo.php\n# Alternatively, delete it via FTP or the cPanel File Manager.§LOC§Apache — .htaccess (if direct deletion is not possible, block access)\n<Files phpinfo.php>\n    Order allow,deny\n    Deny from all\n</Files>', '2026-03-20 13:48:06'),
(387, 21, 'exposure', 'high', 'Adminer Database Tool Exposed', 'An Adminer database management tool is publicly accessible. This provides a graphical interface to the database, which attackers can use to read/write data.', 'https://nicedefenceacademy.com/adminer.php', NULL, '\r\n\r\n\r\n\r\nLogin - Adminer\r\n\r\n\n\r\n\r\n\r\n\r\n\r\n\r\nmixin(document.body, {onkeydown: bodyKeydown, onclick: bodyClick, onload: partial(verifyVersion, \'4.7.7\', \'adm', 'Remove Adminer from the production server or restrict access to trusted IP addresses only.§WHERE§§LOC§Option 1 — Delete the file (Recommended)\nrm /var/www/yourdomain/public/adminer.php§LOC§Option 2 — Apache .htaccess (restrict access to a specific trusted IP)\n<Files adminer.php>\n    Order deny,allow\n    Deny from all\n    Allow from 203.0.113.10  # Replace with your trusted IP address\n</Files>§LOC§Option 3 — Nginx configuration (restrict access to a specific trusted IP)\nlocation /adminer.php {\n    allow 203.0.113.10;  # Replace with your trusted IP address\n    deny all;\n}', '2026-03-20 13:48:06'),
(388, 21, 'csrf', 'medium', 'CSRF Token Missing on POST Form', 'A POST form at https://nicedefenceacademy.com has no detectable CSRF token. Attackers can trick authenticated users into submitting forged requests from a malicious site.', 'https://nicedefenceacademy.com', NULL, 'No CSRF token field found in form', 'Add a CSRF token to every state-changing form. In CI4, CSRF protection is built-in — ensure $config->CSRFProtection = true in Security.php and the token field is included in forms.', '2026-03-20 13:48:08'),
(389, 21, 'csrf', 'medium', 'CSRF Token Missing on POST Form', 'A POST form at https://nicedefenceacademy.com/home/login_user has no detectable CSRF token. Attackers can trick authenticated users into submitting forged requests from a malicious site.', 'https://nicedefenceacademy.com/home/login_user', NULL, 'No CSRF token field found in form', 'Add a CSRF token to every state-changing form. In CI4, CSRF protection is built-in — ensure $config->CSRFProtection = true in Security.php and the token field is included in forms.', '2026-03-20 13:48:08'),
