(400, 21, 'headers', 'medium', 'External Script Without Subresource Integrity (SRI)', 'An external JavaScript file is loaded from \'https://js.stripe.com/v2/\' without a Subresource Integrity (integrity) attribute. If the CDN or external host is compromised, attackers can inject malicious code that will execute on your site.', 'https://nicedefenceacademy.com', NULL, '&lt;script type=&quot;text/javascript&quot; src=&quot;https://js.stripe.com/v2/&quot;&gt;', 'Add an integrity attribute with the base64-encoded SHA-384 hash of the script. Generate it at: https://www.srihash.org/. Example: <script src=\"...\" integrity=\"sha384-...\" crossorigin=\"anonymous\">', '2026-03-20 13:48:29'),
(401, 21, 'headers', 'low', 'External Stylesheet Without Subresource Integrity (SRI)', 'An external CSS file is loaded from \'https://fonts.googleapis.com/css2?family=Nunito:ital,wght@0,800;0,900;1,800;1,900&display=swap\' without a Subresource Integrity attribute. A compromised CDN can inject malicious CSS to perform UI redressing or data exfiltration.', 'https://nicedefenceacademy.com', NULL, '&lt;link rel=&quot;stylesheet&quot; href=&quot;https://fonts.googleapis.com/css2?family=Nunito:ital,wght@0,800;0,900;1,800;1,900&amp;display=swap&quot;&gt;', 'Add an integrity attribute to all external stylesheets. Generate hashes at srihash.org.', '2026-03-20 13:48:29'),
(402, 22, 'headers', 'high', 'Missing HSTS Header (Strict-Transport-Security)', 'Without HSTS, browsers may connect over HTTP even when HTTPS is available, enabling downgrade attacks and cookie theft.', 'https://e-academy.kamleshyadav.com', NULL, 'Header \'strict-transport-security\' absent', 'Add the Strict-Transport-Security header to force browsers to always use HTTPS for this domain.\nValue: Strict-Transport-Security: max-age=31536000; includeSubDomains; preload§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Strict-Transport-Security: max-age=31536000; includeSubDomains; preload\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php (create a new filter or add to an existing one)\n$response->setHeader(\'Strict-Transport-Security\', \'max-age=31536000; includeSubDomains; preload\');\n// Then register in app/Config/Filters.php: $globals[\'after\'][] = \\App\\Filters\\SecurityHeaders::class;', '2026-03-20 13:51:47'),
(403, 22, 'headers', 'medium', 'Missing X-Frame-Options Header', 'Without this header the page can be embedded in an iframe on a malicious site, enabling clickjacking attacks that trick users into clicking hidden elements.', 'https://e-academy.kamleshyadav.com', NULL, 'Header \'x-frame-options\' absent', 'Add the X-Frame-Options header to prevent your pages from being embedded in iframes on other sites.\nValue: X-Frame-Options: SAMEORIGIN§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Frame-Options \"SAMEORIGIN\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Frame-Options \"SAMEORIGIN\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Frame-Options: SAMEORIGIN\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Frame-Options\', \'SAMEORIGIN\');', '2026-03-20 13:51:47'),
(404, 22, 'headers', 'low', 'Missing X-Content-Type-Options Header', 'Without this header browsers may \"sniff\" the content type and execute files as a different type, enabling MIME-type confusion attacks.', 'https://e-academy.kamleshyadav.com', NULL, 'Header \'x-content-type-options\' absent', 'Add the X-Content-Type-Options header to prevent browsers from guessing the content type.\nValue: X-Content-Type-Options: nosniff§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Content-Type-Options \"nosniff\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Content-Type-Options \"nosniff\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Content-Type-Options: nosniff\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Content-Type-Options\', \'nosniff\');', '2026-03-20 13:51:47'),
(405, 22, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://e-academy.kamleshyadav.com', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-20 13:51:47'),
(406, 22, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'https://e-academy.kamleshyadav.com', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-03-20 13:51:47'),
(407, 22, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://e-academy.kamleshyadav.com', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-03-20 13:51:47'),
(408, 22, 'cookies', 'low', 'Cookie \'ci_session\' Missing Secure Flag', 'The cookie \'ci_session\' can be sent over unencrypted HTTP connections, making it vulnerable to interception.', 'https://e-academy.kamleshyadav.com', NULL, 'Set-Cookie: ci_session=fd37f350c9285e39174be09dd1b064f4568ccb68; expires=Fri, 20-Mar-2026 15:51:46 GMT; Max-Age=7200; path=/; HttpOnly', 'Set the Secure flag on the \'ci_session\' cookie to ensure it is transmitted only over HTTPS connections.§WHERE§§LOC§CodeIgniter 4 — app/Config/Session.php\npublic bool $cookieSecure = true;§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'secure\' => true, \'httponly\' => true, \'samesite\' => \'Lax\']);§LOC§Apache — .htaccess (PHP flag override)\nphp_flag session.cookie_secure 1', '2026-03-20 13:51:47'),
(409, 22, 'cookies', 'low', 'Cookie \'ci_session\' Missing SameSite Attribute', 'Without SameSite, the cookie is sent on cross-site requests, making it vulnerable to CSRF attacks.', 'https://e-academy.kamleshyadav.com', NULL, 'Set-Cookie: ci_session=fd37f350c9285e39174be09dd1b064f4568ccb68; expires=Fri, 20-Mar-2026 15:51:46 GMT; Max-Age=7200; path=/; HttpOnly', 'Set the SameSite attribute on the \'ci_session\' cookie to restrict it from being sent on cross-site requests.§WHERE§§LOC§CodeIgniter 4 — app/Config/Cookie.php\npublic string $samesite = \'Lax\';  // Accepted values: \'Strict\', \'Lax\', or \'None\'§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'samesite\' => \'Lax\', \'secure\' => true, \'httponly\' => true]);§LOC§Apache — .htaccess\nphp_value session.cookie_samesite Lax', '2026-03-20 13:51:47'),
(410, 22, 'csrf', 'medium', 'CSRF Token Missing on POST Form', 'A POST form at https://e-academy.kamleshyadav.com/front_ajax/login has no detectable CSRF token. Attackers can trick authenticated users into submitting forged requests from a malicious site.', 'https://e-academy.kamleshyadav.com/front_ajax/login', NULL, 'No CSRF token field found in form', 'Add a CSRF token to every state-changing form. In CI4, CSRF protection is built-in — ensure $config->CSRFProtection = true in Security.php and the token field is included in forms.', '2026-03-20 13:51:49'),
(411, 22, 'headers', 'medium', 'External Script Without Subresource Integrity (SRI)', 'An external JavaScript file is loaded from \'https://checkout.razorpay.com/v1/checkout.js\' without a Subresource Integrity (integrity) attribute. If the CDN or external host is compromised, attackers can inject malicious code that will execute on your site.', 'https://e-academy.kamleshyadav.com', NULL, '&lt;script src=&quot;https://checkout.razorpay.com/v1/checkout.js&quot;&gt;', 'Add an integrity attribute with the base64-encoded SHA-384 hash of the script. Generate it at: https://www.srihash.org/. Example: <script src=\"...\" integrity=\"sha384-...\" crossorigin=\"anonymous\">', '2026-03-20 13:51:54'),
(412, 23, 'exposure', 'high', 'Command Injection Risk — Shell Execution Function', 'A shell execution function is used. If user input reaches this call it enables Remote Code Execution.', 'bookly-pro/admin/bookly-pro-admin-class.php', 'exec($command, $output, $returnCode);*/', 'bookly-pro/admin/bookly-pro-admin-class.php:2244', 'Avoid shell functions where possible. If necessary, use escapeshellarg()/escapeshellcmd() and whitelist allowed values.', '2026-03-20 13:53:04'),
(413, 23, 'exposure', 'high', 'Command Injection Risk — Shell Execution Function', 'A shell execution function is used. If user input reaches this call it enables Remote Code Execution.', 'bookly-pro/admin/bookly-pro-admin-class.php', 'exec($command, $output, $returnCode);', 'bookly-pro/admin/bookly-pro-admin-class.php:2284', 'Avoid shell functions where possible. If necessary, use escapeshellarg()/escapeshellcmd() and whitelist allowed values.', '2026-03-20 13:53:04'),
(414, 23, 'xss', 'high', 'jQuery .html() With Dynamic Content — XSS Risk', 'jQuery .html() is used with a dynamic (non-literal) argument. If the value contains user-controlled data, this directly injects unescaped HTML into the DOM — a classic XSS vector.', 'bookly-pro/admin/js/bookly-pro-admin.js', '$(\'#gpt_post_content\').html(html_tem);', 'bookly-pro/admin/js/bookly-pro-admin.js:432', 'Use .text() for plain text output. If HTML is required, sanitize the value with DOMPurify before passing to .html(). Example: $(el).html(DOMPurify.sanitize(content)).', '2026-03-20 13:53:04'),
