INSERT INTO `qa_scan_findings` (`id`, `scan_id`, `category`, `severity`, `title`, `description`, `affected_url`, `payload`, `evidence`, `remediation`, `found_at`) VALUES
(422, 23, 'xss', 'low', 'window.open() Without noopener — Reverse Tabnabbing Risk', 'window.open() is called without passing rel=\"noopener noreferrer\". The opened page gains a reference to the opener window via window.opener, allowing it to redirect the original page to a phishing URL.', 'bookly-pro/admin/js/bookly-pro-admin.js', '//window.open(res_data.pdf_url);', 'bookly-pro/admin/js/bookly-pro-admin.js:1063', 'Pass the noopener feature string: window.open(url, \'_blank\', \'noopener,noreferrer\'). This removes the opener reference from the child window.', '2026-03-20 13:53:04'),
(423, 23, 'xss', 'high', 'jQuery .html() With Dynamic Content — XSS Risk', 'jQuery .html() is used with a dynamic (non-literal) argument. If the value contains user-controlled data, this directly injects unescaped HTML into the DOM — a classic XSS vector.', 'bookly-pro/admin/js/bookly-pro-admin.js', '$(\'#\'+current_id).html(editorContent);', 'bookly-pro/admin/js/bookly-pro-admin.js:1389', 'Use .text() for plain text output. If HTML is required, sanitize the value with DOMPurify before passing to .html(). Example: $(el).html(DOMPurify.sanitize(content)).', '2026-03-20 13:53:04'),
(424, 23, 'xss', 'high', 'DOM-Based XSS — URL/Referrer Data Used in Unsafe Sink', 'Data from location.href, location.search, location.hash, document.referrer, or window.name is used in a dangerous DOM sink (innerHTML, document.write, eval). This is a classic DOM-based XSS pattern — attackers can craft URLs with malicious scripts.', 'bookly-pro/admin/js/html2canvas.min.js', '***************************************************************************** */var r=function(A,e){return(r=Object.setPrototypeOf||{__proto__:[]}instanceof Array&&function(A,e){A.__proto__=e}||function(A,e){for(var t in e)Object.prototype.hasOwnProperty.call(e,t)&&(A[t]=e[t])})(A,e)};function A(A,e…', 'bookly-pro/admin/js/html2canvas.min.js:20', 'Never pass URL parameters, hash values, or referrer data to innerHTML or eval. Use textContent instead of innerHTML. Use DOMPurify to sanitize any HTML from untrusted sources.', '2026-03-20 13:53:04'),
(425, 23, 'xss', 'high', 'jQuery .html() With Dynamic Content — XSS Risk', 'jQuery .html() is used with a dynamic (non-literal) argument. If the value contains user-controlled data, this directly injects unescaped HTML into the DOM — a classic XSS vector.', 'bookly-pro/admin/js/jquery.PrintArea.js', 'htm += \'<div \' + attributes + \'>\' + $(ele).html() + \'</div>\';', 'bookly-pro/admin/js/jquery.PrintArea.js:129', 'Use .text() for plain text output. If HTML is required, sanitize the value with DOMPurify before passing to .html(). Example: $(el).html(DOMPurify.sanitize(content)).', '2026-03-20 13:53:04'),
(426, 23, 'redirect', 'medium', 'Client-Side Open Redirect Risk — Dynamic location Assignment', 'window.location or location.href is assigned a dynamic value (not a hardcoded string). If this value is derived from URL parameters or user input, attackers can redirect users to malicious sites.', 'bookly-pro/admin/js/jquery.PrintArea.js', 'var windowAttr = \"location=yes,statusbar=no,directories=no,menubar=no,titlebar=no,toolbar=no,dependent=no\";', 'bookly-pro/admin/js/jquery.PrintArea.js:183', 'Validate redirect destinations against an allowlist. Use relative paths for internal redirects. Never redirect to a URL derived from untrusted input.', '2026-03-20 13:53:04'),
(427, 23, 'xss', 'low', 'window.open() Without noopener — Reverse Tabnabbing Risk', 'window.open() is called without passing rel=\"noopener noreferrer\". The opened page gains a reference to the opener window via window.opener, allowing it to redirect the original page to a phishing URL.', 'bookly-pro/admin/js/jquery.PrintArea.js', 'var newWin = window.open( \"\", \"_blank\",  windowAttr );', 'bookly-pro/admin/js/jquery.PrintArea.js:187', 'Pass the noopener feature string: window.open(url, \'_blank\', \'noopener,noreferrer\'). This removes the opener reference from the child window.', '2026-03-20 13:53:04'),
(428, 23, 'redirect', 'medium', 'Client-Side Open Redirect Risk — Dynamic location Assignment', 'window.location or location.href is assigned a dynamic value (not a hardcoded string). If this value is derived from URL parameters or user input, attackers can redirect users to malicious sites.', 'bookly-pro/admin/js/jspdf.umd.js', 'if (popup) popup.location.href = url;else location = url;', 'bookly-pro/admin/js/jspdf.umd.js:243', 'Validate redirect destinations against an allowlist. Use relative paths for internal redirects. Never redirect to a URL derived from untrusted input.', '2026-03-20 13:53:05'),
(429, 23, 'redirect', 'medium', 'Client-Side Open Redirect Risk — Dynamic location Assignment', 'window.location or location.href is assigned a dynamic value (not a hardcoded string). If this value is derived from URL parameters or user input, attackers can redirect users to malicious sites.', 'bookly-pro/admin/js/jspdf.umd.js', 'if (popup) popup.location = url;else location.href = url;', 'bookly-pro/admin/js/jspdf.umd.js:251', 'Validate redirect destinations against an allowlist. Use relative paths for internal redirects. Never redirect to a URL derived from untrusted input.', '2026-03-20 13:53:05'),
(430, 23, '', 'medium', 'Math.random() Used for Security-Sensitive Value', 'Math.random() is not cryptographically secure. Using it to generate tokens, CSRF nonces, session IDs, or passwords makes them predictable and guessable.', 'bookly-pro/admin/js/jspdf.umd.js', 'var token = Math.random().toString(35);', 'bookly-pro/admin/js/jspdf.umd.js:1005', 'Use window.crypto.getRandomValues() for browser-side security tokens: const array = new Uint32Array(1); crypto.getRandomValues(array); Or use crypto.randomUUID() for UUIDs.', '2026-03-20 13:53:05'),
(431, 23, 'xss', 'medium', 'XSS Risk — document.write()', 'document.write() can introduce XSS vulnerabilities and is considered deprecated.', 'bookly-pro/admin/js/jspdf.umd.js', 'nW.document.write(htmlForNewWindow);', 'bookly-pro/admin/js/jspdf.umd.js:3910', 'Replace document.write() with DOM manipulation methods (createElement, appendChild, textContent).', '2026-03-20 13:53:05'),
(432, 23, 'xss', 'medium', 'XSS Risk — document.write()', 'document.write() can introduce XSS vulnerabilities and is considered deprecated.', 'bookly-pro/admin/js/jspdf.umd.js', 'PDFjsNewWindow.document.write(htmlForPDFjsNewWindow);', 'bookly-pro/admin/js/jspdf.umd.js:3925', 'Replace document.write() with DOM manipulation methods (createElement, appendChild, textContent).', '2026-03-20 13:53:05'),
(433, 23, 'xss', 'medium', 'XSS Risk — document.write()', 'document.write() can introduce XSS vulnerabilities and is considered deprecated.', 'bookly-pro/admin/js/jspdf.umd.js', 'dataURLNewWindow.document.write(htmlForDataURLNewWindow);', 'bookly-pro/admin/js/jspdf.umd.js:3945', 'Replace document.write() with DOM manipulation methods (createElement, appendChild, textContent).', '2026-03-20 13:53:05'),
(434, 23, 'redirect', 'medium', 'Client-Side Open Redirect Risk — Dynamic location Assignment', 'window.location or location.href is assigned a dynamic value (not a hardcoded string). If this value is derived from URL parameters or user input, attackers can redirect users to malicious sites.', 'bookly-pro/admin/js/jspdf.umd.js', 'return globalObject.document.location.href = this.output(\"datauristring\", options);', 'bookly-pro/admin/js/jspdf.umd.js:3958', 'Validate redirect destinations against an allowlist. Use relative paths for internal redirects. Never redirect to a URL derived from untrusted input.', '2026-03-20 13:53:05'),
(435, 23, 'xss', 'medium', 'setTimeout/setInterval With String Argument — Eval-Like Execution', 'Passing a string (instead of a function reference) to setTimeout() or setInterval() causes JavaScript to evaluate it via eval(), enabling code injection if the string contains user-controlled data.', 'bookly-pro/admin/js/jspdf.umd.js', 'setTimeout(saveAs.unload, 911);', 'bookly-pro/admin/js/jspdf.umd.js:6468', 'Always pass a function reference: setTimeout(() => doSomething(), delay). Never pass a string as the first argument to setTimeout or setInterval.', '2026-03-20 13:53:05'),
(436, 23, 'xss', 'medium', 'setTimeout/setInterval With String Argument — Eval-Like Execution', 'Passing a string (instead of a function reference) to setTimeout() or setInterval() causes JavaScript to evaluate it via eval(), enabling code injection if the string contains user-controlled data.', 'bookly-pro/admin/js/jspdf.umd.js', 'setTimeout(saveAs.unload, 911);', 'bookly-pro/admin/js/jspdf.umd.js:6480', 'Always pass a function reference: setTimeout(() => doSomething(), delay). Never pass a string as the first argument to setTimeout or setInterval.', '2026-03-20 13:53:05'),
(437, 23, 'xss', 'medium', 'XSS Risk — Dynamic innerHTML Assignment', 'Setting innerHTML with a dynamic value can enable XSS if the value contains attacker-controlled content.', 'bookly-pro/admin/js/jspdf.umd.js', 'el.innerHTML = opt.dompurify.sanitize(opt.innerHTML);', 'bookly-pro/admin/js/jspdf.umd.js:15817', 'Use textContent for plain text. If HTML is needed, sanitize with DOMPurify before assigning.', '2026-03-20 13:53:05'),
(438, 23, 'redirect', 'medium', 'Client-Side Open Redirect Risk — Dynamic location Assignment', 'window.location or location.href is assigned a dynamic value (not a hardcoded string). If this value is derived from URL parameters or user input, attackers can redirect users to malicious sites.', 'bookly-pro/admin/js/jspdf.umd.js', 'return document.location.href = this.prop.img.src;', 'bookly-pro/admin/js/jspdf.umd.js:16201', 'Validate redirect destinations against an allowlist. Use relative paths for internal redirects. Never redirect to a URL derived from untrusted input.', '2026-03-20 13:53:05'),
(439, 23, 'redirect', 'medium', 'Client-Side Open Redirect Risk — Dynamic location Assignment', 'window.location or location.href is assigned a dynamic value (not a hardcoded string). If this value is derived from URL parameters or user input, attackers can redirect users to malicious sites.', 'bookly-pro/admin/js/jspdf.umd.js', 'var location = line * this.width * 4 + x * 8 * 4;', 'bookly-pro/admin/js/jspdf.umd.js:19429', 'Validate redirect destinations against an allowlist. Use relative paths for internal redirects. Never redirect to a URL derived from untrusted input.', '2026-03-20 13:53:05'),
