(446, 23, 'disclosure', 'low', 'External Stylesheet Loaded Without Subresource Integrity (SRI)', 'A <link rel=\"stylesheet\"> loads CSS from an external CDN without an integrity attribute. A compromised CDN can serve malicious CSS (e.g., keyloggers via CSS attribute selectors).', 'bookly-pro/admin/mpdf/generated.html', '<link rel=\"stylesheet\" href=\"https://fonts.googleapis.com/css2?family=inherit&display=swapp\">', 'bookly-pro/admin/mpdf/generated.html:7', 'Add integrity and crossorigin: <link rel=\"stylesheet\" href=\"...\" integrity=\"sha384-...\" crossorigin=\"anonymous\">.', '2026-03-20 13:53:05'),
(447, 23, 'disclosure', 'low', 'External Stylesheet Loaded Without Subresource Integrity (SRI)', 'A <link rel=\"stylesheet\"> loads CSS from an external CDN without an integrity attribute. A compromised CDN can serve malicious CSS (e.g., keyloggers via CSS attribute selectors).', 'bookly-pro/admin/mpdf/generated.html', '<link rel=\"stylesheet\" href=\"https://fonts.googleapis.com/css2?family=inherit&display=swap\">', 'bookly-pro/admin/mpdf/generated.html:8', 'Add integrity and crossorigin: <link rel=\"stylesheet\" href=\"...\" integrity=\"sha384-...\" crossorigin=\"anonymous\">.', '2026-03-20 13:53:05'),
(448, 23, 'disclosure', 'info', 'Content Security Policy (CSP) Meta Tag Not Found', 'No Content-Security-Policy meta tag was found in this HTML file. Without CSP, the browser has no instruction to restrict which resources can be loaded, making XSS attacks easier to exploit.', 'bookly-pro/admin/mpdf/generated.html', 'generated.html', 'bookly-pro/admin/mpdf/generated.html', 'Add a CSP meta tag in <head>: <meta http-equiv=\"Content-Security-Policy\" content=\"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\';\">. Alternatively, set the header server-side for stronger enforcement.', '2026-03-20 13:53:05'),
(449, 23, 'xss', 'medium', 'javascript: Protocol in href — XSS Vector', 'A link uses href=\"javascript:...\". This executes JavaScript when the link is clicked and is a common XSS injection point if the URL can be influenced by user input.', 'bookly-pro/admin/mpdf/generated.html', '<a href=\"javascript:void(0);\" cbc-open-modal=\"childBookGalleryModal\" data-image-id=\"setimag_1\" class=\"cbc-modal-link\" style=\"display: none;\"><span>Change Image</span></a>', 'bookly-pro/admin/mpdf/generated.html:709', 'Replace javascript: href links with proper <button> elements or event listeners. Validate all URL values before rendering in href attributes.', '2026-03-20 13:53:05'),
(450, 23, 'xss', 'medium', 'javascript: Protocol in href — XSS Vector', 'A link uses href=\"javascript:...\". This executes JavaScript when the link is clicked and is a common XSS injection point if the URL can be influenced by user input.', 'bookly-pro/admin/mpdf/generated.html', '<a href=\"javascript:void(0);\" class=\"cbc-edit-data-btn\" style=\"display: none;\">', 'bookly-pro/admin/mpdf/generated.html:713', 'Replace javascript: href links with proper <button> elements or event listeners. Validate all URL values before rendering in href attributes.', '2026-03-20 13:53:05'),
(451, 23, 'xss', 'medium', 'javascript: Protocol in href — XSS Vector', 'A link uses href=\"javascript:...\". This executes JavaScript when the link is clicked and is a common XSS injection point if the URL can be influenced by user input.', 'bookly-pro/admin/mpdf/generated.html', '<a href=\"javascript:void(0);\" class=\"cbc-edit-data-btn\" style=\"display: none;\">', 'bookly-pro/admin/mpdf/generated.html:717', 'Replace javascript: href links with proper <button> elements or event listeners. Validate all URL values before rendering in href attributes.', '2026-03-20 13:53:05'),
