(506, 23, 'disclosure', 'info', 'Content Security Policy (CSP) Meta Tag Not Found', 'No Content-Security-Policy meta tag was found in this HTML file. Without CSP, the browser has no instruction to restrict which resources can be loaded, making XSS attacks easier to exploit.', 'bookly-pro/admin/mpdf/template.html', 'template.html', 'bookly-pro/admin/mpdf/template.html', 'Add a CSP meta tag in <head>: <meta http-equiv=\"Content-Security-Policy\" content=\"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\';\">. Alternatively, set the header server-side for stronger enforcement.', '2026-03-20 13:53:06'),
(507, 23, 'xss', 'medium', 'javascript: Protocol in href — XSS Vector', 'A link uses href=\"javascript:...\". This executes JavaScript when the link is clicked and is a common XSS injection point if the URL can be influenced by user input.', 'bookly-pro/admin/mpdf/template.html', '<a href=\"javascript:void(0);\" cbc-open-modal=\"childBookGalleryModal\" id=\"setimage_0\"', 'bookly-pro/admin/mpdf/template.html:221', 'Replace javascript: href links with proper <button> elements or event listeners. Validate all URL values before rendering in href attributes.', '2026-03-20 13:53:06'),
(508, 23, 'xss', 'medium', 'javascript: Protocol in href — XSS Vector', 'A link uses href=\"javascript:...\". This executes JavaScript when the link is clicked and is a common XSS injection point if the URL can be influenced by user input.', 'bookly-pro/admin/mpdf/template.html', '<a href=\"javascript:void(0);\" cbc-open-modal=\"childBookGalleryModal\" id=\"setimage_2\" class=\"cbc-modal-link\"><span>Change Image</span></a>', 'bookly-pro/admin/mpdf/template.html:237', 'Replace javascript: href links with proper <button> elements or event listeners. Validate all URL values before rendering in href attributes.', '2026-03-20 13:53:06'),
(509, 23, 'disclosure', 'low', 'Potential Mixed Content — HTTP Resource Reference', 'An HTTP (non-HTTPS) URL is referenced for a resource. On HTTPS pages this causes mixed-content warnings.', 'bookly-pro/admin/mpdf/template.html', '<!-- <img src=\"http://ankitmodi/bookly-pro/wp-content/plugins/bookly-pro/admin/images/image2.png\" alt=\"\" class=\"style-one-avtar\"> -->', 'bookly-pro/admin/mpdf/template.html:219', 'Update all resource URLs to use HTTPS or protocol-relative URLs (//example.com/...).', '2026-03-20 13:53:06');
INSERT INTO `qa_scan_findings` (`id`, `scan_id`, `category`, `severity`, `title`, `description`, `affected_url`, `payload`, `evidence`, `remediation`, `found_at`) VALUES
