(513, 23, 'exposure', 'medium', 'Potentially Unsafe unserialize() Usage', 'unserialize() can be dangerous if the serialized data originates from any untrusted source (cookies, database values from user-controlled data, file uploads, etc.).', 'bookly-pro/bookly-wp-autoupdate.php', 'return unserialize($request[\'body\']);', 'bookly-pro/bookly-wp-autoupdate.php:115', 'Audit the source of all data passed to unserialize(). Prefer JSON for data interchange. If you must use serialize/unserialize, add a HMAC integrity check.', '2026-03-20 13:53:09'),
(514, 24, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Apache\",\"category\":\"Server\"},{\"name\":\"CodeIgniter\",\"category\":\"Framework\"},{\"name\":\"PHP\",\"category\":\"Language\"},{\"name\":\"jQuery\",\"category\":\"JavaScript Library\"}]', 'https://www.tusitio.vidractor.com/login', NULL, NULL, NULL, '2026-03-27 06:53:33'),
(515, 24, 'headers', 'medium', 'Missing X-Frame-Options Header', 'Without this header the page can be embedded in an iframe on a malicious site, enabling clickjacking attacks that trick users into clicking hidden elements.', 'https://www.tusitio.vidractor.com/login', NULL, 'Header \'x-frame-options\' absent', 'Add the X-Frame-Options header to prevent your pages from being embedded in iframes on other sites.\nValue: X-Frame-Options: SAMEORIGIN§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Frame-Options \"SAMEORIGIN\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Frame-Options \"SAMEORIGIN\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Frame-Options: SAMEORIGIN\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Frame-Options\', \'SAMEORIGIN\');', '2026-03-27 06:53:33'),
(516, 24, 'headers', 'low', 'Missing X-Content-Type-Options Header', 'Without this header browsers may \"sniff\" the content type and execute files as a different type, enabling MIME-type confusion attacks.', 'https://www.tusitio.vidractor.com/login', NULL, 'Header \'x-content-type-options\' absent', 'Add the X-Content-Type-Options header to prevent browsers from guessing the content type.\nValue: X-Content-Type-Options: nosniff§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Content-Type-Options \"nosniff\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Content-Type-Options \"nosniff\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Content-Type-Options: nosniff\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Content-Type-Options\', \'nosniff\');', '2026-03-27 06:53:33'),
(517, 24, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://www.tusitio.vidractor.com/login', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-27 06:53:33'),
(518, 24, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'https://www.tusitio.vidractor.com/login', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-03-27 06:53:33'),
(519, 24, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://www.tusitio.vidractor.com/login', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-03-27 06:53:33'),
(520, 24, 'cookies', 'low', 'Cookie \'ci_session\' Missing Secure Flag', 'The cookie \'ci_session\' can be sent over unencrypted HTTP connections, making it vulnerable to interception.', 'https://www.tusitio.vidractor.com/login', NULL, 'Set-Cookie: ci_session=f0f20c08409e946d633b6db53e2464359406bbce; path=/; HttpOnly', 'Set the Secure flag on the \'ci_session\' cookie to ensure it is transmitted only over HTTPS connections.§WHERE§§LOC§CodeIgniter 4 — app/Config/Session.php\npublic bool $cookieSecure = true;§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'secure\' => true, \'httponly\' => true, \'samesite\' => \'Lax\']);§LOC§Apache — .htaccess (PHP flag override)\nphp_flag session.cookie_secure 1', '2026-03-27 06:53:33'),
(521, 24, 'cookies', 'low', 'Cookie \'ci_session\' Missing SameSite Attribute', 'Without SameSite, the cookie is sent on cross-site requests, making it vulnerable to CSRF attacks.', 'https://www.tusitio.vidractor.com/login', NULL, 'Set-Cookie: ci_session=f0f20c08409e946d633b6db53e2464359406bbce; path=/; HttpOnly', 'Set the SameSite attribute on the \'ci_session\' cookie to restrict it from being sent on cross-site requests.§WHERE§§LOC§CodeIgniter 4 — app/Config/Cookie.php\npublic string $samesite = \'Lax\';  // Accepted values: \'Strict\', \'Lax\', or \'None\'§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'samesite\' => \'Lax\', \'secure\' => true, \'httponly\' => true]);§LOC§Apache — .htaccess\nphp_value session.cookie_samesite Lax', '2026-03-27 06:53:33'),
(522, 24, 'exposure', 'info', 'Robots.txt Found', 'robots.txt was found. Disallowed paths may reveal hidden or sensitive areas of the application.', 'https://www.tusitio.vidractor.com/robots.txt', NULL, 'User-agent: *\nAllow: /\nSitemap:https://vidractor.com/sitemap.xml\nSitemap:https://vidractor.com/sitemap-1.xml\nSitemap:https://vidractor.com/sitemap-2.x', 'Review your robots.txt file. Avoid listing sensitive paths in Disallow directives — this inadvertently reveals hidden areas to attackers.§WHERE§§LOC§File Location — robots.txt (project root or public/ folder)\n# Avoid listing sensitive paths — it signals their existence to attackers:\n# Disallow: /admin/    ← reveals admin panel location\n# Disallow: /backup/   ← reveals backup directory\n# Use proper access controls (authentication) rather than robots.txt for security.§LOC§Recommended safe robots.txt\nUser-agent: *\nDisallow:\n# Or to block all crawlers entirely:\n# User-agent: *\n# Disallow: /', '2026-03-27 06:53:39'),
(523, 24, 'input_security', 'high', 'Password Field in GET Form — Credentials Exposed in URL', 'The form at \'https://www.tusitio.vidractor.com/login\' uses GET method with a password field. Passwords appear in the browser URL bar, server access logs, browser history, and HTTP Referer headers — permanently exposing credentials.', 'https://www.tusitio.vidractor.com/login', NULL, 'Field \'usererpass\' type=password, form method=GET', 'Change form method to POST. Never submit passwords or sensitive data via GET.', '2026-03-27 06:54:03'),
(524, 24, 'input_security', 'low', 'Password Input Missing autocomplete Attribute', 'A password field was found without autocomplete=\"off\", \"current-password\", or \"new-password\". Browsers may cache the password, which is a risk on shared devices.', 'https://www.tusitio.vidractor.com/login', NULL, '&lt;input type=&quot;password&quot; name=&quot;usererpass&quot; class=&quot;vp-input-field&quot; value=&quot;&quot; placeholder=&quot;Enter your password&quot; /&gt;', 'Add autocomplete=\"current-password\" for login forms or autocomplete=\"new-password\" for registration/password-change forms.', '2026-03-27 06:54:03'),
(525, 25, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Nginx\",\"category\":\"Server\",\"version\":\"1.18.0\"},{\"name\":\"Next.js\",\"category\":\"Framework\"},{\"name\":\"React\",\"category\":\"JavaScript Library\"},{\"name\":\"Node.js\",\"category\":\"Language\"}]', 'https://pixascheduler.pixelnx.com', NULL, NULL, NULL, '2026-03-27 07:10:43'),
(526, 25, 'headers', 'medium', 'Missing X-Frame-Options Header', 'Without this header the page can be embedded in an iframe on a malicious site, enabling clickjacking attacks that trick users into clicking hidden elements.', 'https://pixascheduler.pixelnx.com', NULL, 'Header \'x-frame-options\' absent', 'Add the X-Frame-Options header to prevent your pages from being embedded in iframes on other sites.\nValue: X-Frame-Options: SAMEORIGIN§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Frame-Options \"SAMEORIGIN\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Frame-Options \"SAMEORIGIN\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Frame-Options: SAMEORIGIN\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Frame-Options\', \'SAMEORIGIN\');', '2026-03-27 07:10:43'),
(527, 25, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://pixascheduler.pixelnx.com', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-27 07:10:43'),
(528, 25, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'https://pixascheduler.pixelnx.com', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-03-27 07:10:43'),
(529, 25, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://pixascheduler.pixelnx.com', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-03-27 07:10:43'),
(530, 25, 'disclosure', 'low', 'Server Version Disclosed in Header', 'The Server response header exposes version information: \"nginx/1.18.0 (Ubuntu)\". Attackers use this to look up known exploits for that specific version.', 'https://pixascheduler.pixelnx.com', NULL, 'Server: nginx/1.18.0 (Ubuntu)', 'Suppress server version information in all HTTP responses.§WHERE§§LOC§Apache — /etc/apache2/apache2.conf or /etc/httpd/conf/httpd.conf\nServerTokens Prod\nServerSignature Off§LOC§Nginx — /etc/nginx/nginx.conf (http {} block ke andar)\nserver_tokens off;§LOC§Apache .htaccess (agar apache2 mod_headers enabled ho)\nHeader unset Server\nHeader always set Server \"Apache\"', '2026-03-27 07:10:43'),
(531, 25, 'disclosure', 'low', 'X-Powered-By Header Exposes Technology Stack', 'The X-Powered-By header reveals: \"Next.js\". This helps attackers identify the technology and target known vulnerabilities.', 'https://pixascheduler.pixelnx.com', NULL, 'X-Powered-By: Next.js', 'Remove the X-Powered-By response header to avoid disclosing the technology stack.§WHERE§§LOC§PHP — php.ini (server-wide setting)\nexpose_php = Off§LOC§PHP — app/Controllers/BaseController.php (add to the initialize() method)\nheader_remove(\'X-Powered-By\');§LOC§Apache — .htaccess\nHeader unset X-Powered-By§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block me)\nfastcgi_hide_header X-Powered-By;', '2026-03-27 07:10:43'),
(532, 25, 'input_security', 'high', 'Password Field in GET Form — Credentials Exposed in URL', 'The form at \'https://pixascheduler.pixelnx.com/user/dashboard\' uses GET method with a password field. Passwords appear in the browser URL bar, server access logs, browser history, and HTTP Referer headers — permanently exposing credentials.', 'https://pixascheduler.pixelnx.com/user/dashboard', NULL, 'Field \'password\' type=password, form method=GET', 'Change form method to POST. Never submit passwords or sensitive data via GET.', '2026-03-27 07:11:46'),
(533, 25, 'cors', 'medium', 'CORS Wildcard Origin — Access-Control-Allow-Origin: *', 'The server returns \"Access-Control-Allow-Origin: *\" which allows any website to make cross-origin requests and read the response. While not dangerous for public APIs, it can expose sensitive data on authenticated endpoints.', 'https://pixascheduler.pixelnx.com', NULL, 'Access-Control-Allow-Origin: *', 'Replace wildcard with a specific allowlist of trusted origins. Use dynamic reflection only with a strict validation against a known-good list.', '2026-03-27 07:11:47'),
(534, 25, 'exposure', 'medium', 'Potentially Dangerous HTTP Methods Enabled (PUT/DELETE)', 'The server advertises support for PUT or DELETE methods. If WebDAV or REST endpoints are improperly secured, attackers can upload, modify, or delete server files.', 'https://pixascheduler.pixelnx.com', NULL, 'Allowed methods: ACCESS-CONTROL-ALLOW-METHODS: GET,POST,PUT,PATCH,DELETE,OPTIONS,HEAD ', 'Disable WebDAV if not required. Ensure PUT/DELETE endpoints require authentication and strict authorization checks. Restrict to specific paths only.', '2026-03-27 07:11:47'),
(535, 25, 'headers', 'medium', 'External Script Without Subresource Integrity (SRI)', 'An external JavaScript file is loaded from \'https://www.googletagmanager.com/gtag/js?id=G-67KB8PBYTK\' without a Subresource Integrity (integrity) attribute. If the CDN or external host is compromised, attackers can inject malicious code that will execute on your site.', 'https://pixascheduler.pixelnx.com', NULL, '&lt;script async=&quot;&quot; src=&quot;https://www.googletagmanager.com/gtag/js?id=G-67KB8PBYTK&quot;&gt;', 'Add an integrity attribute with the base64-encoded SHA-384 hash of the script. Generate it at: https://www.srihash.org/. Example: <script src=\"...\" integrity=\"sha384-...\" crossorigin=\"anonymous\">', '2026-03-27 07:11:48'),
(536, 25, 'headers', 'low', 'External Stylesheet Without Subresource Integrity (SRI)', 'An external CSS file is loaded from \'https://fonts.googleapis.com/css2?family=Be+Vietnam+Pro:wght@400;500;600;700&amp;display=swap\' without a Subresource Integrity attribute. A compromised CDN can inject malicious CSS to perform UI redressing or data exfiltration.', 'https://pixascheduler.pixelnx.com', NULL, '&lt;link href=&quot;https://fonts.googleapis.com/css2?family=Be+Vietnam+Pro:wght@400;500;600;700&amp;amp;display=swap&quot; rel=&quot;stylesheet&quot;/&gt;', 'Add an integrity attribute to all external stylesheets. Generate hashes at srihash.org.', '2026-03-27 07:11:48'),
(537, 26, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Apache\",\"category\":\"Server\"}]', 'https://www.tusitio.vidractor.com', NULL, NULL, NULL, '2026-03-27 07:20:45'),
(538, 26, 'headers', 'medium', 'Missing X-Frame-Options Header', 'Without this header the page can be embedded in an iframe on a malicious site, enabling clickjacking attacks that trick users into clicking hidden elements.', 'https://www.tusitio.vidractor.com', NULL, 'Header \'x-frame-options\' absent', 'Add the X-Frame-Options header to prevent your pages from being embedded in iframes on other sites.\nValue: X-Frame-Options: SAMEORIGIN§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Frame-Options \"SAMEORIGIN\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Frame-Options \"SAMEORIGIN\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Frame-Options: SAMEORIGIN\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Frame-Options\', \'SAMEORIGIN\');', '2026-03-27 07:20:45'),
(539, 26, 'headers', 'low', 'Missing X-Content-Type-Options Header', 'Without this header browsers may \"sniff\" the content type and execute files as a different type, enabling MIME-type confusion attacks.', 'https://www.tusitio.vidractor.com', NULL, 'Header \'x-content-type-options\' absent', 'Add the X-Content-Type-Options header to prevent browsers from guessing the content type.\nValue: X-Content-Type-Options: nosniff§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Content-Type-Options \"nosniff\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Content-Type-Options \"nosniff\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Content-Type-Options: nosniff\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Content-Type-Options\', \'nosniff\');', '2026-03-27 07:20:45'),
(540, 26, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://www.tusitio.vidractor.com', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-27 07:20:45'),
(541, 26, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'https://www.tusitio.vidractor.com', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-03-27 07:20:45'),
(542, 26, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://www.tusitio.vidractor.com', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-03-27 07:20:45'),
(543, 26, 'exposure', 'high', 'Git Repository Exposed (.git)', 'The .git directory is publicly accessible. Attackers can reconstruct the full source code, find credentials committed to history, and identify vulnerabilities.', 'https://www.tusitio.vidractor.com/.git/HEAD', NULL, 'Array\n(\n    [data] => \n)\n\n\n\n\n404 Page Not Found\n\nbody {\n    margin: 0;\n    padding: 0;\n    background: #fffafa;\n}\n/* devanagari */\n@font-face {\n    fo', 'Block all public access to the .git directory immediately.§WHERE§§LOC§Apache — .htaccess (project root or public/ folder)\nRedirectMatch 404 /\\.git\n# Alternative:\n<DirectoryMatch \"^/.*/\\.git/\">\n    Order deny,allow\n    Deny from all\n</DirectoryMatch>§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (inside the server {} block)\nlocation ~ /\\.git {\n    deny all;\n    return 404;\n}§LOC§Best Practice — Set the correct document root\n# The document root should point to the public/ folder, not the project root.\n# Apache VirtualHost:  DocumentRoot /var/www/yourdomain/public\n# Nginx:               root /var/www/yourdomain/public;', '2026-03-27 07:20:47'),
(544, 26, 'exposure', 'medium', 'phpinfo() Page Exposed', 'A phpinfo() page is publicly accessible. It reveals PHP version, loaded modules, file paths, environment variables and security configuration — all useful for an attacker.', 'https://www.tusitio.vidractor.com/phpinfo.php', NULL, 'Array\n(\n    [data] => \n)\n\n\n\n\n404 Page Not Found\n\nbody {\n    margin: 0;\n    padding: 0;\n    background: #fffafa;\n}\n/* devanagari */\n@font-face {\n    fo', 'Remove this file from the production server immediately.§WHERE§§LOC§Delete the file via SSH\nrm /var/www/yourdomain/public/phpinfo.php\n# Alternatively, delete it via FTP or the cPanel File Manager.§LOC§Apache — .htaccess (if direct deletion is not possible, block access)\n<Files phpinfo.php>\n    Order allow,deny\n    Deny from all\n</Files>', '2026-03-27 07:20:48'),
(545, 26, 'exposure', 'high', 'Config Backup File Exposed', 'A PHP configuration backup file is publicly accessible.', 'https://www.tusitio.vidractor.com/config.php.bak', NULL, 'Array\n(\n    [data] => \n)\n\n\n\n\n404 Page Not Found\n\nbody {\n    margin: 0;\n    padding: 0;\n    background: #fffafa;\n}\n/* devanagari */\n@font-face {\n    fo', 'Remove this backup file and ensure no backup files are ever stored inside the web root.§WHERE§§LOC§Delete the file via SSH\nrm /var/www/yourdomain/public/config.php.bak§LOC§Apache — .htaccess (block all backup file extensions)\n<FilesMatch \"\\.(bak|backup|old|orig|save)$\">\n    Order allow,deny\n    Deny from all\n</FilesMatch>', '2026-03-27 07:20:49'),
(546, 26, 'exposure', 'high', 'Adminer Database Tool Exposed', 'An Adminer database management tool is publicly accessible. This provides a graphical interface to the database, which attackers can use to read/write data.', 'https://www.tusitio.vidractor.com/adminer.php', NULL, 'Array\n(\n    [data] => \n)\n\n\n\n\n404 Page Not Found\n\nbody {\n    margin: 0;\n    padding: 0;\n    background: #fffafa;\n}\n/* devanagari */\n@font-face {\n    fo', 'Remove Adminer from the production server or restrict access to trusted IP addresses only.§WHERE§§LOC§Option 1 — Delete the file (Recommended)\nrm /var/www/yourdomain/public/adminer.php§LOC§Option 2 — Apache .htaccess (restrict access to a specific trusted IP)\n<Files adminer.php>\n    Order deny,allow\n    Deny from all\n    Allow from 203.0.113.10  # Replace with your trusted IP address\n</Files>§LOC§Option 3 — Nginx configuration (restrict access to a specific trusted IP)\nlocation /adminer.php {\n    allow 203.0.113.10;  # Replace with your trusted IP address\n    deny all;\n}', '2026-03-27 07:20:50'),
(547, 26, 'exposure', 'low', 'Apache Server Status Exposed', 'Apache mod_status is publicly accessible, revealing active requests, IPs, and performance data.', 'https://www.tusitio.vidractor.com/server-status', NULL, 'Array\n(\n    [data] => \n)\n\n\n\n\n404 Page Not Found\n\nbody {\n    margin: 0;\n    padding: 0;\n    background: #fffafa;\n}\n/* devanagari */\n@font-face {\n    fo', 'Restrict public access to the Apache server status page.§WHERE§§LOC§Apache — /etc/apache2/mods-enabled/status.conf\n<Location /server-status>\n    SetHandler server-status\n    Order deny,allow\n    Deny from all\n    Allow from 127.0.0.1\n    Allow from ::1\n</Location>§LOC§Apache — .htaccess (alternative method)\n<IfModule mod_rewrite.c>\n    RewriteRule ^server-status - [F,L]\n</IfModule>', '2026-03-27 07:20:51'),
(548, 26, 'exposure', 'info', 'Robots.txt Found', 'robots.txt was found. Disallowed paths may reveal hidden or sensitive areas of the application.', 'https://www.tusitio.vidractor.com/robots.txt', NULL, 'User-agent: *\nAllow: /\nSitemap:https://vidractor.com/sitemap.xml\nSitemap:https://vidractor.com/sitemap-1.xml\nSitemap:https://vidractor.com/sitemap-2.x', 'Review your robots.txt file. Avoid listing sensitive paths in Disallow directives — this inadvertently reveals hidden areas to attackers.§WHERE§§LOC§File Location — robots.txt (project root or public/ folder)\n# Avoid listing sensitive paths — it signals their existence to attackers:\n# Disallow: /admin/    ← reveals admin panel location\n# Disallow: /backup/   ← reveals backup directory\n# Use proper access controls (authentication) rather than robots.txt for security.§LOC§Recommended safe robots.txt\nUser-agent: *\nDisallow:\n# Or to block all crawlers entirely:\n# User-agent: *\n# Disallow: /', '2026-03-27 07:20:52'),
(549, 27, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Apache\",\"category\":\"Server\"}]', 'https://vidractor.com', NULL, NULL, NULL, '2026-03-27 07:28:44'),
