(565, 29, 'headers', 'low', 'Missing X-Content-Type-Options Header', 'Without this header browsers may \"sniff\" the content type and execute files as a different type, enabling MIME-type confusion attacks.', 'https://www.tusitio.vidractor.com', NULL, 'Header \'x-content-type-options\' absent', 'Add the X-Content-Type-Options header to prevent browsers from guessing the content type.\nValue: X-Content-Type-Options: nosniff§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Content-Type-Options \"nosniff\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Content-Type-Options \"nosniff\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Content-Type-Options: nosniff\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Content-Type-Options\', \'nosniff\');', '2026-03-27 07:40:58'),
(566, 29, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://www.tusitio.vidractor.com', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-27 07:40:58'),
(567, 29, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'https://www.tusitio.vidractor.com', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-03-27 07:40:58');
INSERT INTO `qa_scan_findings` (`id`, `scan_id`, `category`, `severity`, `title`, `description`, `affected_url`, `payload`, `evidence`, `remediation`, `found_at`) VALUES
(568, 29, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://www.tusitio.vidractor.com', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-03-27 07:40:58'),
(569, 29, 'exposure', 'info', 'Robots.txt Found', 'robots.txt was found. Disallowed paths may reveal hidden or sensitive areas of the application.', 'https://www.tusitio.vidractor.com/robots.txt', NULL, 'User-agent: *\nAllow: /\nSitemap:https://vidractor.com/sitemap.xml\nSitemap:https://vidractor.com/sitemap-1.xml\nSitemap:https://vidractor.com/sitemap-2.xml\nSitemap:https://vidractor.com/sitemap-3.xml\nSit', 'Review your robots.txt file. Avoid listing sensitive paths in Disallow directives — this inadvertently reveals hidden areas to attackers.§WHERE§§LOC§File Location — robots.txt (project root or public/ folder)\n# Avoid listing sensitive paths — it signals their existence to attackers:\n# Disallow: /admin/    ← reveals admin panel location\n# Disallow: /backup/   ← reveals backup directory\n# Use proper access controls (authentication) rather than robots.txt for security.§LOC§Recommended safe robots.txt\nUser-agent: *\nDisallow:\n# Or to block all crawlers entirely:\n# User-agent: *\n# Disallow: /', '2026-03-27 07:41:05'),
(570, 30, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Apache\",\"category\":\"Server\"},{\"name\":\"jQuery\",\"category\":\"JavaScript Library\"}]', 'https://www.tusitio.vidractor.com/login', NULL, NULL, NULL, '2026-03-27 07:42:15'),
(571, 30, 'headers', 'medium', 'Missing X-Frame-Options Header', 'Without this header the page can be embedded in an iframe on a malicious site, enabling clickjacking attacks that trick users into clicking hidden elements.', 'https://www.tusitio.vidractor.com/login', NULL, 'Header \'x-frame-options\' absent', 'Add the X-Frame-Options header to prevent your pages from being embedded in iframes on other sites.\nValue: X-Frame-Options: SAMEORIGIN§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Frame-Options \"SAMEORIGIN\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Frame-Options \"SAMEORIGIN\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Frame-Options: SAMEORIGIN\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Frame-Options\', \'SAMEORIGIN\');', '2026-03-27 07:42:15'),
(572, 30, 'headers', 'low', 'Missing X-Content-Type-Options Header', 'Without this header browsers may \"sniff\" the content type and execute files as a different type, enabling MIME-type confusion attacks.', 'https://www.tusitio.vidractor.com/login', NULL, 'Header \'x-content-type-options\' absent', 'Add the X-Content-Type-Options header to prevent browsers from guessing the content type.\nValue: X-Content-Type-Options: nosniff§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Content-Type-Options \"nosniff\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Content-Type-Options \"nosniff\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Content-Type-Options: nosniff\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Content-Type-Options\', \'nosniff\');', '2026-03-27 07:42:15'),
(573, 30, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://www.tusitio.vidractor.com/login', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-27 07:42:15'),
(574, 30, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'https://www.tusitio.vidractor.com/login', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-03-27 07:42:15'),
(575, 30, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://www.tusitio.vidractor.com/login', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-03-27 07:42:15'),
(576, 30, 'exposure', 'info', 'Robots.txt Found', 'robots.txt was found. Disallowed paths may reveal hidden or sensitive areas of the application.', 'https://www.tusitio.vidractor.com/robots.txt', NULL, 'User-agent: *\nAllow: /\nSitemap:https://vidractor.com/sitemap.xml\nSitemap:https://vidractor.com/sitemap-1.xml\nSitemap:https://vidractor.com/sitemap-2.xml\nSitemap:https://vidractor.com/sitemap-3.xml\nSit', 'Review your robots.txt file. Avoid listing sensitive paths in Disallow directives — this inadvertently reveals hidden areas to attackers.§WHERE§§LOC§File Location — robots.txt (project root or public/ folder)\n# Avoid listing sensitive paths — it signals their existence to attackers:\n# Disallow: /admin/    ← reveals admin panel location\n# Disallow: /backup/   ← reveals backup directory\n# Use proper access controls (authentication) rather than robots.txt for security.§LOC§Recommended safe robots.txt\nUser-agent: *\nDisallow:\n# Or to block all crawlers entirely:\n# User-agent: *\n# Disallow: /', '2026-03-27 07:42:21'),
(577, 30, 'input_security', 'high', 'Password Field in GET Form — Credentials Exposed in URL', 'The form at \'https://www.tusitio.vidractor.com/login\' uses GET method with a password field. Passwords appear in the browser URL bar, server access logs, browser history, and HTTP Referer headers — permanently exposing credentials.', 'https://www.tusitio.vidractor.com/login', NULL, 'Field \'usererpass\' type=password, form method=GET', 'Change form method to POST. Never submit passwords or sensitive data via GET.', '2026-03-27 07:42:46'),
(578, 30, 'input_security', 'low', 'Password Input Missing autocomplete Attribute', 'A password field was found without autocomplete=\"off\", \"current-password\", or \"new-password\". Browsers may cache the password, which is a risk on shared devices.', 'https://www.tusitio.vidractor.com/login', NULL, '&lt;input type=&quot;password&quot; name=&quot;usererpass&quot; class=&quot;vp-input-field&quot; value=&quot;&quot; placeholder=&quot;Enter your password&quot; /&gt;', 'Add autocomplete=\"current-password\" for login forms or autocomplete=\"new-password\" for registration/password-change forms.', '2026-03-27 07:42:46'),
(579, 31, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Cloudflare\",\"category\":\"CDN\"}]', 'https://chatgpt.com', NULL, NULL, NULL, '2026-03-27 07:48:17'),
(580, 31, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://chatgpt.com', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-27 07:48:17'),
(581, 31, 'cookies', 'low', 'Cookie \'__cf_bm\' Missing SameSite Attribute', 'Without SameSite, the cookie is sent on cross-site requests, making it vulnerable to CSRF attacks.', 'https://chatgpt.com', NULL, 'Set-Cookie: __cf_bm=FjY1FtmZfKIGvwNbe_jWlyNJAbfA.ur3w.wYokoxfAE-1774597698.6091993-1.0.1.1-6PZWoILYTY6kGx141em8D3HuR5MBNaFaLcLcpfZDb1gZSVlwgzE6CZvAmu8T8ES8Ht6VScyDF9Az50GMyVUhluRmQ3ohyc6aR6BDNN_9CyjEpPBrTyCYUvZVmYcVY1Wu; HttpOnly; Secure; Path=/; Domain=chatgpt.com; Expires=Fri, 27 Mar 2026 08:18:18 GMT', 'Set the SameSite attribute on the \'__cf_bm\' cookie to restrict it from being sent on cross-site requests.§WHERE§§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'samesite\' => \'Lax\', \'secure\' => true, \'httponly\' => true]);§LOC§Apache — .htaccess\nphp_value session.cookie_samesite Lax', '2026-03-27 07:48:18'),
(582, 31, 'exposure', 'info', 'Robots.txt Found', 'robots.txt was found. Disallowed paths may reveal hidden or sensitive areas of the application.', 'https://chatgpt.com/robots.txt', NULL, '# https://www.robotstxt.org/robotstxt.html\n\nUser-agent: CCBot\nDisallow: /\n\nUser-agent: img2dataset\nDisallow: /\n\nUser-agent: Google-Extended\nDisallow: /\n\nUser-agent: anthropic-ai\nDisallow: /\n\nUser-agen', 'Review your robots.txt file. Avoid listing sensitive paths in Disallow directives — this inadvertently reveals hidden areas to attackers.§WHERE§§LOC§File Location — robots.txt (project root or public/ folder)\n# Avoid listing sensitive paths — it signals their existence to attackers:\n# Disallow: /admin/    ← reveals admin panel location\n# Disallow: /backup/   ← reveals backup directory\n# Use proper access controls (authentication) rather than robots.txt for security.§LOC§Recommended safe robots.txt\nUser-agent: *\nDisallow:\n# Or to block all crawlers entirely:\n# User-agent: *\n# Disallow: /', '2026-03-27 07:48:18'),
(583, 32, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Apache\",\"category\":\"Server\"},{\"name\":\"CodeIgniter\",\"category\":\"Framework\"},{\"name\":\"PHP\",\"category\":\"Language\"},{\"name\":\"jQuery\",\"category\":\"JavaScript Library\"}]', 'https://www.tusitio.vidractor.com', NULL, NULL, NULL, '2026-03-27 07:58:04'),
