(588, 32, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://www.tusitio.vidractor.com', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-03-27 07:58:04'),
(589, 32, 'cookies', 'low', 'Cookie \'ci_session\' Missing Secure Flag', 'The cookie \'ci_session\' can be sent over unencrypted HTTP connections, making it vulnerable to interception.', 'https://www.tusitio.vidractor.com', NULL, 'Set-Cookie: ci_session=f4c5cedb23fa239f4fd83333b618dbd57663fb6c; path=/; HttpOnly', 'Set the Secure flag on the \'ci_session\' cookie to ensure it is transmitted only over HTTPS connections.§WHERE§§LOC§CodeIgniter 4 — app/Config/Session.php\npublic bool $cookieSecure = true;§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'secure\' => true, \'httponly\' => true, \'samesite\' => \'Lax\']);§LOC§Apache — .htaccess (PHP flag override)\nphp_flag session.cookie_secure 1', '2026-03-27 07:58:04'),
(590, 32, 'cookies', 'low', 'Cookie \'ci_session\' Missing SameSite Attribute', 'Without SameSite, the cookie is sent on cross-site requests, making it vulnerable to CSRF attacks.', 'https://www.tusitio.vidractor.com', NULL, 'Set-Cookie: ci_session=f4c5cedb23fa239f4fd83333b618dbd57663fb6c; path=/; HttpOnly', 'Set the SameSite attribute on the \'ci_session\' cookie to restrict it from being sent on cross-site requests.§WHERE§§LOC§CodeIgniter 4 — app/Config/Cookie.php\npublic string $samesite = \'Lax\';  // Accepted values: \'Strict\', \'Lax\', or \'None\'§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'samesite\' => \'Lax\', \'secure\' => true, \'httponly\' => true]);§LOC§Apache — .htaccess\nphp_value session.cookie_samesite Lax', '2026-03-27 07:58:04'),
(591, 32, 'exposure', 'info', 'Robots.txt Found', 'robots.txt was found. Disallowed paths may reveal hidden or sensitive areas of the application.', 'https://www.tusitio.vidractor.com/robots.txt', NULL, 'User-agent: *\nAllow: /\nSitemap:https://vidractor.com/sitemap.xml\nSitemap:https://vidractor.com/sitemap-1.xml\nSitemap:https://vidractor.com/sitemap-2.xml\nSitemap:https://vidractor.com/sitemap-3.xml\nSit', 'Review your robots.txt file. Avoid listing sensitive paths in Disallow directives — this inadvertently reveals hidden areas to attackers.§WHERE§§LOC§File Location — robots.txt (project root or public/ folder)\n# Avoid listing sensitive paths — it signals their existence to attackers:\n# Disallow: /admin/    ← reveals admin panel location\n# Disallow: /backup/   ← reveals backup directory\n# Use proper access controls (authentication) rather than robots.txt for security.§LOC§Recommended safe robots.txt\nUser-agent: *\nDisallow:\n# Or to block all crawlers entirely:\n# User-agent: *\n# Disallow: /', '2026-03-27 07:58:10'),
(592, 32, 'input_security', 'high', 'Password Field in GET Form — Credentials Exposed in URL', 'The form at \'https://www.tusitio.vidractor.com\' uses GET method with a password field. Passwords appear in the browser URL bar, server access logs, browser history, and HTTP Referer headers — permanently exposing credentials.', 'https://www.tusitio.vidractor.com', NULL, 'Field \'usererpass\' type=password, form method=GET', 'Change form method to POST. Never submit passwords or sensitive data via GET.', '2026-03-27 07:58:35'),
(593, 32, 'input_security', 'low', 'Password Input Missing autocomplete Attribute', 'A password field was found without autocomplete=\"off\", \"current-password\", or \"new-password\". Browsers may cache the password, which is a risk on shared devices.', 'https://www.tusitio.vidractor.com', NULL, '&lt;input type=&quot;password&quot; name=&quot;usererpass&quot; class=&quot;vp-input-field&quot; value=&quot;&quot; placeholder=&quot;Enter your password&quot; /&gt;', 'Add autocomplete=\"current-password\" for login forms or autocomplete=\"new-password\" for registration/password-change forms.', '2026-03-27 07:58:35'),
(594, 33, 'connectivity', 'high', 'Target URL Unreachable', 'The scanner could not reach the target URL. The server may be temporarily unavailable, blocking scanner requests, or the URL is incorrect. Full security assessment could not be completed.', 'https://www.zaproxy.org/docs/developer', NULL, 'HTTP response code: 0 (connection failed)', 'Verify the URL is accessible from this server. Check firewall rules, ensure the web server is running, and confirm the URL is correct.', '2026-03-27 12:01:00'),
(595, 34, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Apache\",\"category\":\"Server\"},{\"name\":\"CodeIgniter\",\"category\":\"Framework\"},{\"name\":\"PHP\",\"category\":\"Language\"},{\"name\":\"jQuery\",\"category\":\"JavaScript Library\"}]', 'https://aiautosites.productaccess.in', NULL, NULL, NULL, '2026-03-31 04:29:26'),
(596, 34, 'headers', 'high', 'Missing HSTS Header (Strict-Transport-Security)', 'Without HSTS, browsers may connect over HTTP even when HTTPS is available, enabling downgrade attacks and cookie theft.', 'https://aiautosites.productaccess.in', NULL, 'Header \'strict-transport-security\' absent', 'Add the Strict-Transport-Security header to force browsers to always use HTTPS for this domain.\nValue: Strict-Transport-Security: max-age=31536000; includeSubDomains; preload§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Strict-Transport-Security: max-age=31536000; includeSubDomains; preload\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php (create a new filter or add to an existing one)\n$response->setHeader(\'Strict-Transport-Security\', \'max-age=31536000; includeSubDomains; preload\');\n// Then register in app/Config/Filters.php: $globals[\'after\'][] = \\App\\Filters\\SecurityHeaders::class;', '2026-03-31 04:29:26'),
(597, 34, 'headers', 'medium', 'Missing X-Frame-Options Header', 'Without this header the page can be embedded in an iframe on a malicious site, enabling clickjacking attacks that trick users into clicking hidden elements.', 'https://aiautosites.productaccess.in', NULL, 'Header \'x-frame-options\' absent', 'Add the X-Frame-Options header to prevent your pages from being embedded in iframes on other sites.\nValue: X-Frame-Options: SAMEORIGIN§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Frame-Options \"SAMEORIGIN\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Frame-Options \"SAMEORIGIN\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Frame-Options: SAMEORIGIN\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Frame-Options\', \'SAMEORIGIN\');', '2026-03-31 04:29:26'),
(598, 34, 'headers', 'low', 'Missing X-Content-Type-Options Header', 'Without this header browsers may \"sniff\" the content type and execute files as a different type, enabling MIME-type confusion attacks.', 'https://aiautosites.productaccess.in', NULL, 'Header \'x-content-type-options\' absent', 'Add the X-Content-Type-Options header to prevent browsers from guessing the content type.\nValue: X-Content-Type-Options: nosniff§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Content-Type-Options \"nosniff\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Content-Type-Options \"nosniff\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Content-Type-Options: nosniff\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Content-Type-Options\', \'nosniff\');', '2026-03-31 04:29:26'),
(599, 34, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://aiautosites.productaccess.in', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-31 04:29:26'),
(600, 34, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'https://aiautosites.productaccess.in', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-03-31 04:29:26'),
(601, 34, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://aiautosites.productaccess.in', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-03-31 04:29:26'),
(602, 34, 'cookies', 'low', 'Cookie \'ci_session\' Missing Secure Flag', 'The cookie \'ci_session\' can be sent over unencrypted HTTP connections, making it vulnerable to interception.', 'https://aiautosites.productaccess.in', NULL, 'Set-Cookie: ci_session=fb668804088779b36726555fe74e8851cf305dec; path=/; HttpOnly', 'Set the Secure flag on the \'ci_session\' cookie to ensure it is transmitted only over HTTPS connections.§WHERE§§LOC§CodeIgniter 4 — app/Config/Session.php\npublic bool $cookieSecure = true;§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'secure\' => true, \'httponly\' => true, \'samesite\' => \'Lax\']);§LOC§Apache — .htaccess (PHP flag override)\nphp_flag session.cookie_secure 1', '2026-03-31 04:29:26'),
(603, 34, 'cookies', 'low', 'Cookie \'ci_session\' Missing SameSite Attribute', 'Without SameSite, the cookie is sent on cross-site requests, making it vulnerable to CSRF attacks.', 'https://aiautosites.productaccess.in', NULL, 'Set-Cookie: ci_session=fb668804088779b36726555fe74e8851cf305dec; path=/; HttpOnly', 'Set the SameSite attribute on the \'ci_session\' cookie to restrict it from being sent on cross-site requests.§WHERE§§LOC§CodeIgniter 4 — app/Config/Cookie.php\npublic string $samesite = \'Lax\';  // Accepted values: \'Strict\', \'Lax\', or \'None\'§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'samesite\' => \'Lax\', \'secure\' => true, \'httponly\' => true]);§LOC§Apache — .htaccess\nphp_value session.cookie_samesite Lax', '2026-03-31 04:29:26'),
(604, 34, 'input_security', 'high', 'Password Field in GET Form — Credentials Exposed in URL', 'The form at \'https://aiautosites.productaccess.in\' uses GET method with a password field. Passwords appear in the browser URL bar, server access logs, browser history, and HTTP Referer headers — permanently exposing credentials.', 'https://aiautosites.productaccess.in', NULL, 'Field \'usererpass\' type=password, form method=GET', 'Change form method to POST. Never submit passwords or sensitive data via GET.', '2026-03-31 04:29:54'),
(605, 34, 'headers', 'medium', 'External Script Without Subresource Integrity (SRI)', 'An external JavaScript file is loaded from \'https://www.googletagmanager.com/gtag/js?id=G-V0299FWKYP\' without a Subresource Integrity (integrity) attribute. If the CDN or external host is compromised, attackers can inject malicious code that will execute on your site.', 'https://aiautosites.productaccess.in', NULL, '&lt;script async src=&quot;https://www.googletagmanager.com/gtag/js?id=G-V0299FWKYP&quot;&gt;', 'Add an integrity attribute with the base64-encoded SHA-384 hash of the script. Generate it at: https://www.srihash.org/. Example: <script src=\"...\" integrity=\"sha384-...\" crossorigin=\"anonymous\">', '2026-03-31 04:29:57'),
(606, 34, 'headers', 'low', 'External Stylesheet Without Subresource Integrity (SRI)', 'An external CSS file is loaded from \'https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap\' without a Subresource Integrity attribute. A compromised CDN can inject malicious CSS to perform UI redressing or data exfiltration.', 'https://aiautosites.productaccess.in', NULL, '&lt;link href=&quot;https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&amp;display=swap&quot; rel=&quot;stylesheet&quot;&gt;', 'Add an integrity attribute to all external stylesheets. Generate hashes at srihash.org.', '2026-03-31 04:29:57'),
(607, 35, 'authentication', 'high', 'Session Fixation Vulnerability — Session ID Not Regenerated After Login', 'The session cookie \'ci_session\' has the same value before and after login. This indicates the session ID is not regenerated on authentication. Attackers can set a known session ID (via cross-site scripting or URL parameter) before the victim logs in, then use that same ID to hijack the authenticated session.', 'https://aiautosites.productaccess.in/', NULL, 'Cookie ci_session value unchanged across authentication boundary', 'Call session_regenerate_id(true) immediately after successful login. In CI4, use $this->session->regenerate(true). Ensure the old session is deleted (pass true to delete the old session).', '2026-03-31 11:42:43'),
(608, 35, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Apache\",\"category\":\"Server\"},{\"name\":\"CodeIgniter\",\"category\":\"Framework\"},{\"name\":\"PHP\",\"category\":\"Language\"},{\"name\":\"jQuery\",\"category\":\"JavaScript Library\"}]', 'https://aiautosites.productaccess.in', NULL, NULL, NULL, '2026-03-31 11:42:46'),
