(610, 35, 'headers', 'medium', 'Missing X-Frame-Options Header', 'Without this header the page can be embedded in an iframe on a malicious site, enabling clickjacking attacks that trick users into clicking hidden elements.', 'https://aiautosites.productaccess.in', NULL, 'Header \'x-frame-options\' absent', 'Add the X-Frame-Options header to prevent your pages from being embedded in iframes on other sites.\nValue: X-Frame-Options: SAMEORIGIN§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Frame-Options \"SAMEORIGIN\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Frame-Options \"SAMEORIGIN\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Frame-Options: SAMEORIGIN\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Frame-Options\', \'SAMEORIGIN\');', '2026-03-31 11:42:46'),
(611, 35, 'headers', 'low', 'Missing X-Content-Type-Options Header', 'Without this header browsers may \"sniff\" the content type and execute files as a different type, enabling MIME-type confusion attacks.', 'https://aiautosites.productaccess.in', NULL, 'Header \'x-content-type-options\' absent', 'Add the X-Content-Type-Options header to prevent browsers from guessing the content type.\nValue: X-Content-Type-Options: nosniff§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Content-Type-Options \"nosniff\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Content-Type-Options \"nosniff\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Content-Type-Options: nosniff\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Content-Type-Options\', \'nosniff\');', '2026-03-31 11:42:46'),
(612, 35, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://aiautosites.productaccess.in', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-31 11:42:46'),
(613, 35, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'https://aiautosites.productaccess.in', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-03-31 11:42:46'),
(614, 35, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://aiautosites.productaccess.in', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-03-31 11:42:46'),
(615, 35, 'input_security', 'high', 'Password Field in GET Form — Credentials Exposed in URL', 'The form at \'https://aiautosites.productaccess.in\' uses GET method with a password field. Passwords appear in the browser URL bar, server access logs, browser history, and HTTP Referer headers — permanently exposing credentials.', 'https://aiautosites.productaccess.in', NULL, 'Field \'usererpass\' type=password, form method=GET', 'Change form method to POST. Never submit passwords or sensitive data via GET.', '2026-03-31 11:43:15'),
(616, 35, 'headers', 'medium', 'External Script Without Subresource Integrity (SRI)', 'An external JavaScript file is loaded from \'https://www.googletagmanager.com/gtag/js?id=G-V0299FWKYP\' without a Subresource Integrity (integrity) attribute. If the CDN or external host is compromised, attackers can inject malicious code that will execute on your site.', 'https://aiautosites.productaccess.in', NULL, '&lt;script async src=&quot;https://www.googletagmanager.com/gtag/js?id=G-V0299FWKYP&quot;&gt;', 'Add an integrity attribute with the base64-encoded SHA-384 hash of the script. Generate it at: https://www.srihash.org/. Example: <script src=\"...\" integrity=\"sha384-...\" crossorigin=\"anonymous\">', '2026-03-31 11:43:17'),
(617, 35, 'headers', 'low', 'External Stylesheet Without Subresource Integrity (SRI)', 'An external CSS file is loaded from \'https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap\' without a Subresource Integrity attribute. A compromised CDN can inject malicious CSS to perform UI redressing or data exfiltration.', 'https://aiautosites.productaccess.in', NULL, '&lt;link href=&quot;https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&amp;display=swap&quot; rel=&quot;stylesheet&quot;&gt;', 'Add an integrity attribute to all external stylesheets. Generate hashes at srihash.org.', '2026-03-31 11:43:17'),
(618, 35, 'authentication', 'high', 'No Account Lockout or Rate Limiting on Login Form', 'The login form at \'https://aiautosites.productaccess.in\' does not appear to block or slow down after multiple failed login attempts. This makes the application vulnerable to brute-force and credential-stuffing attacks.', 'https://aiautosites.productaccess.in', NULL, '6 consecutive failed logins received no rate limiting response', 'Implement account lockout (e.g., lock after 5 failed attempts for 15 minutes) or progressive delays. Add CAPTCHA after 3 failed attempts. Consider IP-based rate limiting. Log and alert on repeated failures.', '2026-03-31 11:43:22'),
(619, 35, '', 'medium', 'External iframe Embedded — Potential Phishing Overlay', 'This page embeds an iframe from an external domain (www.googletagmanager.com). External iframes can be used to display fake login forms, phishing messages, or malicious content inside the legitimate page. Attackers who gain control of the embedded domain can immediately present fraudulent content to all visitors.', 'https://aiautosites.productaccess.in', 'iframe src: www.googletagmanager.com/ns.html?id=GTM-M3ZKKJ8V', 'External iframe domain: www.googletagmanager.com', 'Audit all embedded iframes. Only embed trusted, controlled content. Add sandbox attribute to iframes: <iframe sandbox=\"allow-scripts\">. Implement CSP: frame-src \'self\'; to block unapproved iframe sources.', '2026-03-31 11:43:23'),
(620, 35, '', 'medium', 'Password Input Field Found Outside Login Page Context', 'A password input field exists on a page that is not identified as a login page. Pages that unexpectedly contain password fields are common in phishing attacks — the attacker injects a fake credential form into a legitimate page. Verify all password fields are intentional and served over HTTPS.', 'https://aiautosites.productaccess.in', NULL, 'Found 1 password field(s) at: https://aiautosites.productaccess.in', 'Audit all pages containing password fields. Ensure they are served over HTTPS. Add autocomplete=\'current-password\'. Implement CSP to prevent script injection that could add rogue password fields.', '2026-03-31 11:43:23'),
(621, 35, '', 'high', 'Clickjacking — Page Can Be Embedded in External iframes', 'This page is missing both X-Frame-Options and CSP frame-ancestors protection. Attackers can embed this page inside an invisible or transparent iframe on a malicious website and trick users into clicking buttons or links without realising it (UI redress attack). Common targets: account deletion, money transfer, settings changes, one-click purchase buttons.', 'https://aiautosites.productaccess.in', NULL, 'X-Frame-Options: not set | CSP frame-ancestors: not found', 'Add to all responses:\nX-Frame-Options: DENY\nContent-Security-Policy: frame-ancestors \'none\';\n\nApache .htaccess:\nHeader always set X-Frame-Options \"DENY\"\nHeader always set Content-Security-Policy \"frame-ancestors \'none\'\"\n\nNginx:\nadd_header X-Frame-Options \"DENY\" always;\nadd_header Content-Security-Policy \"frame-ancestors \'none\'\" always;', '2026-03-31 11:43:23'),
(622, 35, '', 'medium', 'High-Risk Injection Entry Points Identified — 2 Field(s) Require Validation', 'The scanner identified 2 form field(s) with names commonly targeted in injection attacks (SQL, XSS, command injection, SSRF, path traversal). These parameters should be validated, sanitised, and parameterised. Even if SQL injection tests passed, parameter-based vulnerabilities can emerge after code changes.', 'https://aiautosites.productaccess.in', NULL, 'High-risk fields:\n\'useremail\' at https://aiautosites.productaccess.in\n\'email\' at https://aiautosites.productaccess.in/forget-password', 'For ALL user input that reaches a backend:\n1. SQL: Use prepared statements / parameterised queries. NEVER concatenate user input into SQL.\n2. HTML output: Use htmlspecialchars() / template engine auto-escaping\n3. File paths: Whitelist only allowed values\n4. URLs: Validate scheme + block private IPs\n5. Shell commands: Never pass user input to exec/system/shell_exec\n\nInput validation checklist:\n- Type check (is it really an integer?)\n- Length limits\n- Regex whitelist (allow expected characters only)\n- Reject or encode unexpected characters', '2026-03-31 11:43:24'),
(623, 35, 'authentication', 'high', 'Privileged Endpoint Accessible While Authenticated: /dashboard', 'The endpoint /dashboard returned HTTP 200 with your authenticated session. If this endpoint grants more privileges than expected (admin panel, debug interface, user listing, API config), it represents a privilege escalation or broken access control vulnerability. Attackers who compromise any user account can potentially access admin functionality.', 'https://aiautosites.productaccess.in/dashboard', NULL, 'HTTP 200 · Body length: 1690 chars', 'Implement role-based access control (RBAC) on ALL admin/privileged routes:\n\n// CI4 example:\nif (!session()->get(\'is_admin\')) {\n    return redirect()->to(\'/\')->with(\'error\', \'Access denied\');\n}\n\n// Middleware approach (recommended):\n// Register admin middleware that checks role before every admin controller\n// Log all access attempts to sensitive endpoints\n// Implement IP allowlisting for admin panels', '2026-03-31 11:43:29'),
(624, 35, 'authentication', 'low', 'No Logout Endpoint Detected', 'The scanner could not find a logout endpoint at common paths (/logout, /signout, etc.). If no logout functionality exists, users on shared/public computers cannot terminate their session — their account remains accessible to anyone who uses the browser after them.', 'https://aiautosites.productaccess.in', NULL, 'Checked paths: /logout, /signout, /sign-out, /auth/logout, /account/logout, /user/logout', 'Implement a logout endpoint that:\n1. Destroys the server-side session\n2. Clears all session cookies\n3. Redirects to the login page\n4. Is accessible via POST (not GET, to prevent CSRF-based forced logout)', '2026-03-31 11:43:56'),
(625, 36, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Cloudflare\",\"category\":\"CDN\"}]', 'https://chatgpt.com', NULL, NULL, NULL, '2026-03-31 13:21:12');
INSERT INTO `qa_scan_findings` (`id`, `scan_id`, `category`, `severity`, `title`, `description`, `affected_url`, `payload`, `evidence`, `remediation`, `found_at`) VALUES
(626, 36, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://chatgpt.com', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-31 13:21:12'),
(627, 36, 'cookies', 'low', 'Cookie \'__cf_bm\' Missing SameSite Attribute', 'Without SameSite, the cookie is sent on cross-site requests, making it vulnerable to CSRF attacks.', 'https://chatgpt.com', NULL, 'Set-Cookie: __cf_bm=xXtwrzp06t1ZvGUi7mugd7GlOoaV_tUAt90QydlcAzk-1774963272.5039892-1.0.1.1-yH9MGAgGyiKVHoLp1_HRX.eElRvpQCAl84CUN0DGkz7VgZa_vaUM3OVqgAy_EXVSjsdONJ4DkSrV22XoNH0MGwyykejvkPkq7H_YRoKzmXjEcqqzTJu.97rj.OJRMdsM; HttpOnly; Secure; Path=/; Domain=chatgpt.com; Expires=Tue, 31 Mar 2026 13:51:12 GMT', 'Set the SameSite attribute on the \'__cf_bm\' cookie to restrict it from being sent on cross-site requests.§WHERE§§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'samesite\' => \'Lax\', \'secure\' => true, \'httponly\' => true]);§LOC§Apache — .htaccess\nphp_value session.cookie_samesite Lax', '2026-03-31 13:21:12'),
(628, 36, 'exposure', 'info', 'Robots.txt Found', 'robots.txt was found. Disallowed paths may reveal hidden or sensitive areas of the application.', 'https://chatgpt.com/robots.txt', NULL, '# https://www.robotstxt.org/robotstxt.html\n\nUser-agent: CCBot\nDisallow: /\n\nUser-agent: img2dataset\nDisallow: /\n\nUser-agent: Google-Extended\nDisallow: /\n\nUser-agent: anthropic-ai\nDisallow: /\n\nUser-agen', 'Review your robots.txt file. Avoid listing sensitive paths in Disallow directives — this inadvertently reveals hidden areas to attackers.§WHERE§§LOC§File Location — robots.txt (project root or public/ folder)\n# Avoid listing sensitive paths — it signals their existence to attackers:\n# Disallow: /admin/    ← reveals admin panel location\n# Disallow: /backup/   ← reveals backup directory\n# Use proper access controls (authentication) rather than robots.txt for security.§LOC§Recommended safe robots.txt\nUser-agent: *\nDisallow:\n# Or to block all crawlers entirely:\n# User-agent: *\n# Disallow: /', '2026-03-31 13:21:13'),
(629, 37, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Apache\",\"category\":\"Server\"},{\"name\":\"CodeIgniter\",\"category\":\"Framework\"},{\"name\":\"PHP\",\"category\":\"Language\"},{\"name\":\"jQuery\",\"category\":\"JavaScript Library\"}]', 'https://aiautosites.productaccess.in', NULL, NULL, NULL, '2026-03-31 13:37:26'),
(630, 37, 'headers', 'high', 'Missing HSTS Header (Strict-Transport-Security)', 'Without HSTS, browsers may connect over HTTP even when HTTPS is available, enabling downgrade attacks and cookie theft.', 'https://aiautosites.productaccess.in', NULL, 'Header \'strict-transport-security\' absent', 'Add the Strict-Transport-Security header to force browsers to always use HTTPS for this domain.\nValue: Strict-Transport-Security: max-age=31536000; includeSubDomains; preload§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Strict-Transport-Security: max-age=31536000; includeSubDomains; preload\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php (create a new filter or add to an existing one)\n$response->setHeader(\'Strict-Transport-Security\', \'max-age=31536000; includeSubDomains; preload\');\n// Then register in app/Config/Filters.php: $globals[\'after\'][] = \\App\\Filters\\SecurityHeaders::class;', '2026-03-31 13:37:26'),
(631, 37, 'headers', 'medium', 'Missing X-Frame-Options Header', 'Without this header the page can be embedded in an iframe on a malicious site, enabling clickjacking attacks that trick users into clicking hidden elements.', 'https://aiautosites.productaccess.in', NULL, 'Header \'x-frame-options\' absent', 'Add the X-Frame-Options header to prevent your pages from being embedded in iframes on other sites.\nValue: X-Frame-Options: SAMEORIGIN§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Frame-Options \"SAMEORIGIN\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Frame-Options \"SAMEORIGIN\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Frame-Options: SAMEORIGIN\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Frame-Options\', \'SAMEORIGIN\');', '2026-03-31 13:37:26'),
(632, 37, 'headers', 'low', 'Missing X-Content-Type-Options Header', 'Without this header browsers may \"sniff\" the content type and execute files as a different type, enabling MIME-type confusion attacks.', 'https://aiautosites.productaccess.in', NULL, 'Header \'x-content-type-options\' absent', 'Add the X-Content-Type-Options header to prevent browsers from guessing the content type.\nValue: X-Content-Type-Options: nosniff§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Content-Type-Options \"nosniff\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Content-Type-Options \"nosniff\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Content-Type-Options: nosniff\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Content-Type-Options\', \'nosniff\');', '2026-03-31 13:37:26'),
(633, 37, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://aiautosites.productaccess.in', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-03-31 13:37:26'),
(634, 37, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'https://aiautosites.productaccess.in', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-03-31 13:37:26'),
(635, 37, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://aiautosites.productaccess.in', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-03-31 13:37:26'),
(636, 37, 'cookies', 'low', 'Cookie \'ci_session\' Missing Secure Flag', 'The cookie \'ci_session\' can be sent over unencrypted HTTP connections, making it vulnerable to interception.', 'https://aiautosites.productaccess.in', NULL, 'Set-Cookie: ci_session=04d629d5c208720be3547877a96d47a1dfcd990c; path=/; HttpOnly', 'Set the Secure flag on the \'ci_session\' cookie to ensure it is transmitted only over HTTPS connections.§WHERE§§LOC§CodeIgniter 4 — app/Config/Session.php\npublic bool $cookieSecure = true;§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'secure\' => true, \'httponly\' => true, \'samesite\' => \'Lax\']);§LOC§Apache — .htaccess (PHP flag override)\nphp_flag session.cookie_secure 1', '2026-03-31 13:37:26'),
(637, 37, 'cookies', 'low', 'Cookie \'ci_session\' Missing SameSite Attribute', 'Without SameSite, the cookie is sent on cross-site requests, making it vulnerable to CSRF attacks.', 'https://aiautosites.productaccess.in', NULL, 'Set-Cookie: ci_session=04d629d5c208720be3547877a96d47a1dfcd990c; path=/; HttpOnly', 'Set the SameSite attribute on the \'ci_session\' cookie to restrict it from being sent on cross-site requests.§WHERE§§LOC§CodeIgniter 4 — app/Config/Cookie.php\npublic string $samesite = \'Lax\';  // Accepted values: \'Strict\', \'Lax\', or \'None\'§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'samesite\' => \'Lax\', \'secure\' => true, \'httponly\' => true]);§LOC§Apache — .htaccess\nphp_value session.cookie_samesite Lax', '2026-03-31 13:37:26'),
(638, 37, 'input_security', 'high', 'Password Field in GET Form — Credentials Exposed in URL', 'The form at \'https://aiautosites.productaccess.in\' uses GET method with a password field. Passwords appear in the browser URL bar, server access logs, browser history, and HTTP Referer headers — permanently exposing credentials.', 'https://aiautosites.productaccess.in', NULL, 'Field \'usererpass\' type=password, form method=GET', 'Change form method to POST. Never submit passwords or sensitive data via GET.', '2026-03-31 13:37:55'),
(639, 37, 'headers', 'medium', 'External Script Without Subresource Integrity (SRI)', 'An external JavaScript file is loaded from \'https://www.googletagmanager.com/gtag/js?id=G-V0299FWKYP\' without a Subresource Integrity (integrity) attribute. If the CDN or external host is compromised, attackers can inject malicious code that will execute on your site.', 'https://aiautosites.productaccess.in', NULL, '&lt;script async src=&quot;https://www.googletagmanager.com/gtag/js?id=G-V0299FWKYP&quot;&gt;', 'Add an integrity attribute with the base64-encoded SHA-384 hash of the script. Generate it at: https://www.srihash.org/. Example: <script src=\"...\" integrity=\"sha384-...\" crossorigin=\"anonymous\">', '2026-03-31 13:37:57'),
(640, 37, 'headers', 'low', 'External Stylesheet Without Subresource Integrity (SRI)', 'An external CSS file is loaded from \'https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap\' without a Subresource Integrity attribute. A compromised CDN can inject malicious CSS to perform UI redressing or data exfiltration.', 'https://aiautosites.productaccess.in', NULL, '&lt;link href=&quot;https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&amp;display=swap&quot; rel=&quot;stylesheet&quot;&gt;', 'Add an integrity attribute to all external stylesheets. Generate hashes at srihash.org.', '2026-03-31 13:37:57'),
(641, 37, '', 'medium', 'External iframe Embedded — Potential Phishing Overlay', 'This page embeds an iframe from an external domain (www.googletagmanager.com). External iframes can be used to display fake login forms, phishing messages, or malicious content inside the legitimate page. Attackers who gain control of the embedded domain can immediately present fraudulent content to all visitors.', 'https://aiautosites.productaccess.in', 'iframe src: www.googletagmanager.com/ns.html?id=GTM-M3ZKKJ8V', 'External iframe domain: www.googletagmanager.com', 'Audit all embedded iframes. Only embed trusted, controlled content. Add sandbox attribute to iframes: <iframe sandbox=\"allow-scripts\">. Implement CSP: frame-src \'self\'; to block unapproved iframe sources.', '2026-03-31 13:37:57'),
(642, 37, '', 'medium', 'Password Input Field Found Outside Login Page Context', 'A password input field exists on a page that is not identified as a login page. Pages that unexpectedly contain password fields are common in phishing attacks — the attacker injects a fake credential form into a legitimate page. Verify all password fields are intentional and served over HTTPS.', 'https://aiautosites.productaccess.in', NULL, 'Found 1 password field(s) at: https://aiautosites.productaccess.in', 'Audit all pages containing password fields. Ensure they are served over HTTPS. Add autocomplete=\'current-password\'. Implement CSP to prevent script injection that could add rogue password fields.', '2026-03-31 13:37:57'),
(643, 37, '', 'high', 'Clickjacking — Page Can Be Embedded in External iframes', 'This page is missing both X-Frame-Options and CSP frame-ancestors protection. Attackers can embed this page inside an invisible or transparent iframe on a malicious website and trick users into clicking buttons or links without realising it (UI redress attack). Common targets: account deletion, money transfer, settings changes, one-click purchase buttons.', 'https://aiautosites.productaccess.in', NULL, 'X-Frame-Options: not set | CSP frame-ancestors: not found', 'Add to all responses:\nX-Frame-Options: DENY\nContent-Security-Policy: frame-ancestors \'none\';\n\nApache .htaccess:\nHeader always set X-Frame-Options \"DENY\"\nHeader always set Content-Security-Policy \"frame-ancestors \'none\'\"\n\nNginx:\nadd_header X-Frame-Options \"DENY\" always;\nadd_header Content-Security-Policy \"frame-ancestors \'none\'\" always;', '2026-03-31 13:37:57'),
(644, 37, '', 'medium', 'High-Risk Injection Entry Points Identified — 2 Field(s) Require Validation', 'The scanner identified 2 form field(s) with names commonly targeted in injection attacks (SQL, XSS, command injection, SSRF, path traversal). These parameters should be validated, sanitised, and parameterised. Even if SQL injection tests passed, parameter-based vulnerabilities can emerge after code changes.', 'https://aiautosites.productaccess.in', NULL, 'High-risk fields:\n\'useremail\' at https://aiautosites.productaccess.in\n\'email\' at https://aiautosites.productaccess.in/forget-password', 'For ALL user input that reaches a backend:\n1. SQL: Use prepared statements / parameterised queries. NEVER concatenate user input into SQL.\n2. HTML output: Use htmlspecialchars() / template engine auto-escaping\n3. File paths: Whitelist only allowed values\n4. URLs: Validate scheme + block private IPs\n5. Shell commands: Never pass user input to exec/system/shell_exec\n\nInput validation checklist:\n- Type check (is it really an integer?)\n- Length limits\n- Regex whitelist (allow expected characters only)\n- Reject or encode unexpected characters', '2026-03-31 13:37:59'),
(645, 38, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Apache\",\"category\":\"Server\"},{\"name\":\"CodeIgniter\",\"category\":\"Framework\"},{\"name\":\"PHP\",\"category\":\"Language\"},{\"name\":\"jQuery\",\"category\":\"JavaScript Library\"}]', 'https://hybridai.co.in', NULL, NULL, NULL, '2026-04-01 07:21:09'),
