(647, 38, 'headers', 'medium', 'Missing X-Frame-Options Header', 'Without this header the page can be embedded in an iframe on a malicious site, enabling clickjacking attacks that trick users into clicking hidden elements.', 'https://hybridai.co.in', NULL, 'Header \'x-frame-options\' absent', 'Add the X-Frame-Options header to prevent your pages from being embedded in iframes on other sites.\nValue: X-Frame-Options: SAMEORIGIN§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Frame-Options \"SAMEORIGIN\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Frame-Options \"SAMEORIGIN\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Frame-Options: SAMEORIGIN\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Frame-Options\', \'SAMEORIGIN\');', '2026-04-01 07:21:09'),
(648, 38, 'headers', 'low', 'Missing X-Content-Type-Options Header', 'Without this header browsers may \"sniff\" the content type and execute files as a different type, enabling MIME-type confusion attacks.', 'https://hybridai.co.in', NULL, 'Header \'x-content-type-options\' absent', 'Add the X-Content-Type-Options header to prevent browsers from guessing the content type.\nValue: X-Content-Type-Options: nosniff§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Content-Type-Options \"nosniff\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Content-Type-Options \"nosniff\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Content-Type-Options: nosniff\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Content-Type-Options\', \'nosniff\');', '2026-04-01 07:21:09'),
(649, 38, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://hybridai.co.in', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-04-01 07:21:09'),
(650, 38, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'https://hybridai.co.in', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-04-01 07:21:09'),
(651, 38, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://hybridai.co.in', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-04-01 07:21:09'),
(652, 38, 'cookies', 'low', 'Cookie \'ci_session\' Missing Secure Flag', 'The cookie \'ci_session\' can be sent over unencrypted HTTP connections, making it vulnerable to interception.', 'https://hybridai.co.in', NULL, 'Set-Cookie: ci_session=611b31dac198610d0ac1c532e06e5ab1; expires=Wed, 01 Apr 2026 09:21:09 GMT; Max-Age=7200; path=/; HttpOnly; SameSite=Lax', 'Set the Secure flag on the \'ci_session\' cookie to ensure it is transmitted only over HTTPS connections.§WHERE§§LOC§CodeIgniter 4 — app/Config/Session.php\npublic bool $cookieSecure = true;§LOC§PHP — Use session_set_cookie_params() before session_start()\nsession_set_cookie_params([\'secure\' => true, \'httponly\' => true, \'samesite\' => \'Lax\']);§LOC§Apache — .htaccess (PHP flag override)\nphp_flag session.cookie_secure 1', '2026-04-01 07:21:09'),
(653, 38, 'input_security', 'low', 'Password Input Missing autocomplete Attribute', 'A password field was found without autocomplete=\"off\", \"current-password\", or \"new-password\". Browsers may cache the password, which is a risk on shared devices.', 'https://hybridai.co.in', NULL, '&lt;input type=&quot;password&quot; name=&quot;usererpass&quot; placeholder=&quot;Enter Your Password&quot;  class=&quot;bpcast-pass&quot;/&gt;', 'Add autocomplete=\"current-password\" for login forms or autocomplete=\"new-password\" for registration/password-change forms.', '2026-04-01 07:21:28'),
(654, 38, '', 'medium', 'Password Input Field Found Outside Login Page Context', 'A password input field exists on a page that is not identified as a login page. Pages that unexpectedly contain password fields are common in phishing attacks — the attacker injects a fake credential form into a legitimate page. Verify all password fields are intentional and served over HTTPS.', 'https://hybridai.co.in', NULL, 'Found 1 password field(s) at: https://hybridai.co.in', 'Audit all pages containing password fields. Ensure they are served over HTTPS. Add autocomplete=\'current-password\'. Implement CSP to prevent script injection that could add rogue password fields.', '2026-04-01 07:21:31'),
(655, 38, '', 'high', 'Clickjacking — Page Can Be Embedded in External iframes', 'This page is missing both X-Frame-Options and CSP frame-ancestors protection. Attackers can embed this page inside an invisible or transparent iframe on a malicious website and trick users into clicking buttons or links without realising it (UI redress attack). Common targets: account deletion, money transfer, settings changes, one-click purchase buttons.', 'https://hybridai.co.in', NULL, 'X-Frame-Options: not set | CSP frame-ancestors: not found', 'Add to all responses:\nX-Frame-Options: DENY\nContent-Security-Policy: frame-ancestors \'none\';\n\nApache .htaccess:\nHeader always set X-Frame-Options \"DENY\"\nHeader always set Content-Security-Policy \"frame-ancestors \'none\'\"\n\nNginx:\nadd_header X-Frame-Options \"DENY\" always;\nadd_header Content-Security-Policy \"frame-ancestors \'none\'\" always;', '2026-04-01 07:21:31'),
(656, 39, 'authentication', 'low', 'Login Password Field Missing autocomplete=\"current-password\" or \"off\"', 'The login form password field does not have autocomplete=\"current-password\" or autocomplete=\"off\". On shared/public computers, the browser may cache the password.', 'https://hybridai.co.in/', NULL, '&lt;input type=&quot;password&quot; name=&quot;usererpass&quot; placeholder=&quot;Enter Your Password&quot;  class=&quot;bpcast-pass&quot;/&gt;', 'Add autocomplete=\"current-password\" to login password fields (recommended per WCAG/best practice) or autocomplete=\"off\" if the application is used on shared computers.', '2026-04-01 07:23:18'),
(657, 39, 'authentication', 'high', 'Session Fixation Vulnerability — Session ID Not Regenerated After Login', 'The session cookie \'ci_session\' has the same value before and after login. This indicates the session ID is not regenerated on authentication. Attackers can set a known session ID (via cross-site scripting or URL parameter) before the victim logs in, then use that same ID to hijack the authenticated session.', 'https://hybridai.co.in/', NULL, 'Cookie ci_session value unchanged across authentication boundary', 'Call session_regenerate_id(true) immediately after successful login. In CI4, use $this->session->regenerate(true). Ensure the old session is deleted (pass true to delete the old session).', '2026-04-01 07:23:19'),
(658, 39, '', 'info', 'Technology Stack Detected', '[{\"name\":\"Apache\",\"category\":\"Server\"},{\"name\":\"CodeIgniter\",\"category\":\"Framework\"},{\"name\":\"PHP\",\"category\":\"Language\"},{\"name\":\"jQuery\",\"category\":\"JavaScript Library\"}]', 'https://hybridai.co.in', NULL, NULL, NULL, '2026-04-01 07:23:22'),
(659, 39, 'headers', 'high', 'Missing HSTS Header (Strict-Transport-Security)', 'Without HSTS, browsers may connect over HTTP even when HTTPS is available, enabling downgrade attacks and cookie theft.', 'https://hybridai.co.in', NULL, 'Header \'strict-transport-security\' absent', 'Add the Strict-Transport-Security header to force browsers to always use HTTPS for this domain.\nValue: Strict-Transport-Security: max-age=31536000; includeSubDomains; preload§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Strict-Transport-Security: max-age=31536000; includeSubDomains; preload\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php (create a new filter or add to an existing one)\n$response->setHeader(\'Strict-Transport-Security\', \'max-age=31536000; includeSubDomains; preload\');\n// Then register in app/Config/Filters.php: $globals[\'after\'][] = \\App\\Filters\\SecurityHeaders::class;', '2026-04-01 07:23:22'),
(660, 39, 'headers', 'medium', 'Missing X-Frame-Options Header', 'Without this header the page can be embedded in an iframe on a malicious site, enabling clickjacking attacks that trick users into clicking hidden elements.', 'https://hybridai.co.in', NULL, 'Header \'x-frame-options\' absent', 'Add the X-Frame-Options header to prevent your pages from being embedded in iframes on other sites.\nValue: X-Frame-Options: SAMEORIGIN§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Frame-Options \"SAMEORIGIN\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Frame-Options \"SAMEORIGIN\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Frame-Options: SAMEORIGIN\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Frame-Options\', \'SAMEORIGIN\');', '2026-04-01 07:23:22'),
(661, 39, 'headers', 'low', 'Missing X-Content-Type-Options Header', 'Without this header browsers may \"sniff\" the content type and execute files as a different type, enabling MIME-type confusion attacks.', 'https://hybridai.co.in', NULL, 'Header \'x-content-type-options\' absent', 'Add the X-Content-Type-Options header to prevent browsers from guessing the content type.\nValue: X-Content-Type-Options: nosniff§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set X-Content-Type-Options \"nosniff\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header X-Content-Type-Options \"nosniff\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'X-Content-Type-Options: nosniff\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'X-Content-Type-Options\', \'nosniff\');', '2026-04-01 07:23:22'),
(662, 39, 'headers', 'medium', 'Missing Content-Security-Policy (CSP) Header', 'Without CSP, the browser has no policy to restrict which scripts, styles and resources may load, making XSS attacks significantly more impactful.', 'https://hybridai.co.in', NULL, 'Header \'content-security-policy\' absent', 'Add a Content-Security-Policy header. Start with a strict base and relax as needed.\nBasic safe value: Content-Security-Policy: default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'; img-src \'self\' data:\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Content-Security-Policy \"default-src \'self\'; script-src \'self\'; style-src \'self\' \'unsafe-inline\'\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\"Content-Security-Policy: default-src \'self\'; script-src \'self\'\");§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Content-Security-Policy\', \"default-src \'self\'; script-src \'self\'\");', '2026-04-01 07:23:22'),
(663, 39, 'headers', 'low', 'Missing Referrer-Policy Header', 'Without Referrer-Policy, the full URL (including path and query parameters which may contain sensitive tokens) is sent to third-party sites in the Referer header.', 'https://hybridai.co.in', NULL, 'Header \'referrer-policy\' absent', 'Add the Referrer-Policy header to control how much referrer information is sent.\nValue: Referrer-Policy: strict-origin-when-cross-origin§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Referrer-Policy \"strict-origin-when-cross-origin\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Referrer-Policy \"strict-origin-when-cross-origin\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Referrer-Policy: strict-origin-when-cross-origin\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Referrer-Policy\', \'strict-origin-when-cross-origin\');', '2026-04-01 07:23:22'),
(664, 39, 'headers', 'info', 'Missing Permissions-Policy Header', 'Permissions-Policy controls access to browser APIs (camera, microphone, geolocation). Missing it leaves feature access unrestricted.', 'https://hybridai.co.in', NULL, 'Header \'permissions-policy\' absent', 'Add the Permissions-Policy header to restrict browser feature access.\nValue: Permissions-Policy: camera=(), microphone=(), geolocation=()§WHERE§§LOC§Apache — .htaccess (project root or the public/ document root folder)\nHeader always set Permissions-Policy \"camera=(), microphone=(), geolocation=()\"§LOC§Nginx — /etc/nginx/sites-available/yourdomain.conf (server {} block ke andar)\nadd_header Permissions-Policy \"camera=(), microphone=(), geolocation=()\" always;§LOC§PHP — app/Controllers/BaseController.php (inside the initialize() method)\nheader(\'Permissions-Policy: camera=(), microphone=(), geolocation=()\');§LOC§CodeIgniter 4 — app/Filters/SecurityHeaders.php\n$response->setHeader(\'Permissions-Policy\', \'camera=(), microphone=(), geolocation=()\');', '2026-04-01 07:23:22'),
