/Directory>\\n\\n# Also rename \\/wp-admin\\/ via a security \",\"# Immediate action \\u2014 delete the file:\\nrm \\/path\\/to\\/timthumb.php\\n\\n# Then update ALL WordPress themes and plugins.\\n# Find all copies: find \\/var\\/www -name \'timthumb.php\' 2>\\/dev\\/null\",\"# Delete the file:\\nrm \\/path\\/to\\/eval-stdin.php\\n\\n# Upgrade PHP (7.3.11+ \\/ 7.2.24+ \\/ 7.1.33+)\\n# Review php-fpm.conf \\u2014 ensure PATH_INFO is not enabled unnecessarily\\n# Nginx config fix:\\nlocation ~ \\\\.php$\",\"# Apache \\u2014 block php.cgi in config:\\n<Files php.cgi>\\n  Order deny,allow\\n  Deny from all\\n<\\/Files>\\n\\n# Switch to PHP-FPM (mod_fastcgi or mod_proxy_fcgi) instead of CGI mode.\",\"# Apache \\u2014 disable CGI if not needed:\\na2dismod cgi\\n\\n# Or restrict access:\\n<Directory \\\"\\/var\\/www\\/cgi-bin\\\">\\n  Order deny,allow\\n  Deny from all\\n<\\/Directory>\\n\\n# Review all CGI scripts for injection vulne\",\"# IMMEDIATE RESPONSE REQUIRED:\\n1. Delete the file: rm \\/path\\/to\\/shell.php\\n2. Check all upload directories: find \\/var\\/www -name \'*.php\' -path \'*\\/upload*\'\\n3. Review access logs: grep \'shell.php\' \\/var\\/log\",\"# IMMEDIATE RESPONSE \\u2014 Server is likely compromised:\\n1. rm \\/path\\/to\\/c99.php\\n2. find \\/var\\/www -name \'c99*.php\' -delete\\n3. Isolate server from network if possible\\n4. Audit all PHP files: grep -r \'eval\",\"# IMMEDIATE RESPONSE:\\n1. rm \\/path\\/to\\/r57.php\\n2. find \\/var\\/www -name \'r57*.php\' -delete\\n3. Full forensic audit required\\n4. grep -r \'c99\\\\|r57\\\\|b374k\\\\|wso\\\\|shell\' \\/var\\/www\\/ --include=\'*.php\' -l\\n5. Change\",\"# IMMEDIATE RESPONSE:\\n1. rm \\/path\\/to\\/b374k.php\\n2. Find all web shells: grep -r \'eval(base64_decode\\\\|gzinflate\\\\|str_rot13\' \\/var\\/www\\/ --include=\'*.php\' -l\\n3. Take server offline if data breach is suspec\",\"# IMMEDIATE RESPONSE:\\n1. Delete: rm \\/path\\/to\\/wso.php\\n2. Scan: find \\/var\\/www -name \'wso*.php\' -o -name \'*.ph\' -o -name \'*.phtml\' 2>\\/dev\\/null\\n3. Audit access logs for POST requests to PHP files in uploa\",\"Set allow_url_fopen=Off in php.ini; replace file_get_contents(URL) calls with cURL\"],\"scanned_at\":\"2026-04-01 13:21:37\"}', 1, '2026-04-01 13:21:37');
